WITH payload AS (
  SELECT $RISQQ41${"questions":[{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.29","internal_question_no":"04A.029","question_sort_key":4102900.071,"question_text":"Are portable fire extinguishers being maintained in good order, and ready for immediate use in an emergency?","guide_to_inspection":"Although there is no clear requirement concerning the validity date of powder in the FSS Code, it is generally considered necessary to\nrefill the powder every 5 or 6 years, in principle. It is highly recommended that spare charges should also be replaced at the same time\nconsidering age deterioration, even though the expiration date of the charges is not specified by the manufacturer. In light of the above\nsituation, crew shall consider replacing the spare charges of powder fire extinguishers at the same intervals as the refilling intervals\nspecified by the manufacturer (Class NK Bulletin 20, 2020).\nPeriodic inspections and maintenance of portable fire extinguisher:\nExtinguishers should be subject to periodical inspections in accordance with the manufacturer’s instructions and serviced at intervals\nnot exceeding one year.\n> At least one extinguisher of each type manufactured in the same year and kept on board a ship should be test discharged at five\nyearly intervals (as part of a fire drill).\n> All extinguishers together with propellant cartridges should be hydraulically tested in accordance with the recognized standard or\nthe manufacturer’s instruction at intervals not exceeding ten years.\n> Service and inspection should only be undertaken by, or under the supervision of, a person with demonstrable competence,\nbased on the inspection guide in table 9.1.3 in Resolution A.951 (23).\n> Records of inspections should be maintained. The records should show the date of inspection, the type of maintenance carried\nout and whether a pressure test was performed.\n> Extinguishers should be provided with a visual indication of discharge.\n> Instructions for recharging extinguishers should be supplied by the manufacturer and be available for use on board.\n(Resolution A.951 (23)/Improved Guidelines for Marine Portable Fire Extinguishers, 2004)\nSpare charges shall be provided for 100% of the first ten extinguishers and 50% of the remaining fire extinguishers capable of being\nrecharged on board. Not more than sixty total spare charges are required.\nFor fire extinguishers which cannot be recharged on board additional portable fire extinguishers of the same quantity, type, capacity,\nand number as determined in paragraph above shall be provided in lieu of spare charges.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":60,"source_page_end":61,"raw_source_text":"Are portable fire extinguishers being maintained in good order, and ready for immediate use in\nan emergency? (V)\nGuide to Inspection\nAlthough there is no clear requirement concerning the validity date of powder in the FSS Code, it is generally considered necessary to\nrefill the powder every 5 or 6 years, in principle. It is highly recommended that spare charges should also be replaced at the same time\nconsidering age deterioration, even though the expiration date of the charges is not specified by the manufacturer. In light of the above\nsituation, crew shall consider replacing the spare charges of powder fire extinguishers at the same intervals as the refilling intervals\nspecified by the manufacturer (Class NK Bulletin 20, 2020).\nPeriodic inspections and maintenance of portable fire extinguisher:\nExtinguishers should be subject to periodical inspections in accordance with the manufacturer’s instructions and serviced at intervals\nnot exceeding one year.\n> At least one extinguisher of each type manufactured in the same year and kept on board a ship should be test discharged at five\nyearly intervals (as part of a fire drill).\n> All extinguishers together with propellant cartridges should be hydraulically tested in accordance with the recognized standard or\nthe manufacturer’s instruction at intervals not exceeding ten years.\n> Service and inspection should only be undertaken by, or under the supervision of, a person with demonstrable competence,\nbased on the inspection guide in table 9.1.3 in Resolution A.951 (23).\n> Records of inspections should be maintained. The records should show the date of inspection, the type of maintenance carried\nout and whether a pressure test was performed.\n> Extinguishers should be provided with a visual indication of discharge.\n> Instructions for recharging extinguishers should be supplied by the manufacturer and be available for use on board.\n(Resolution A.951 (23)/Improved Guidelines for Marine Portable Fire Extinguishers, 2004)\nSpare charges shall be provided for 100% of the first ten extinguishers and 50% of the remaining fire extinguishers capable of being\nrecharged on board. Not more than sixty total spare charges are required.\nFor fire extinguishers which cannot be recharged on board additional portable fire extinguishers of the same quantity, type, capacity,\nand number as determined in paragraph above shall be provided in lieu of spare charges.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.30","internal_question_no":"04A.030","question_sort_key":4103000.072,"question_text":"Are firemen’s outfits including their equipment, two-way portable radiotelephone apparatus for fire-fighter’s communication and breathing apparatus in good condition, fit for purpose and available for instant use?","guide_to_inspection":"Each firefighting team shall be equipped with portable two-way radiotelephones for the purposes of communication. The\nefficient use of these radios shall not be inhibited by the use of any firefighting equipment, including the firefighter’s outfit.\nTo be fit for purpose a firefighter wearing a fireman’s outfit and Breathing Apparatus must be able to communicate clearly\nand without restriction with the Command and Control team.\nWhen possible, the inspector should evaluate the effectiveness of the two-way radio communication equipment provided.\nRecord a Finding if there are insufficient intrinsically safe two-way portable radios for the number of fire teams on the muster\nlist, or if wearing a fireman’s outfit and Breathing Apparatus hinders the firefighter’s ability to operate the radios while\nfighting a fire.\nOne complete fireman’s outfit should include following items:\n> SCBA (self-contained breathing apparatus)\n> Fireman’s suit\n> Fireman’s helmet\n> Fireman’s rubber boots\n> Explosion proof light\nFireproof lifeline combination rope of wire and nylon or hemp rope, complete with safety snap hook. Available in 30, 40 and 50\nmetre lengths.\n> Fire axe\n> Fireman safety belt\n“Compressed air breathing apparatus shall be fitted with an audible alarm and a visual or other device which will alert\nthe user before the volume of the air in the cylinder has been reduced to no less than 200 litres.” This applies to ship’s\nconstructed (keel laid) on or after 1 July 2014. Ships constructed (keel laid) before 1 July 2014 must comply no later than 1\nJuly 2019.\n“An on-board means of recharging breathing apparatus cylinders used during drills shall be provided or a suitable number of\nspare cylinders shall be carried on board to replace those used.” This applies to all ships on or after 1 July 2014.\n“For ships constructed on or after 1 July 2014, a minimum of two two-way portable radiotelephone apparatus for each fire\nparty for fire-fighter’s communication shall be carried on board. These two-way portable radiotelephone apparatuses shall\nbe of an explosion-proof type or intrinsically safe. Ships constructed before 1 July 2014 shall comply with the requirements\nof this paragraph not later than the first safety equipment survey after 1 July 2018.”\n(SOLAS 74, 2020)\nThe two-way portable radio should comply with the IACS UI SC291.\nThe purpose of these fire-fighter radios is to provide a dedicated means of communication between the team of fire fighters\nentering the space and the crew member located outside the space who is assigned to control this team.\nThe two-way portable radio, intended for use by the fire fighters in the Fire Party, should be capable of being used by crew\nmembers wearing full fire fighter suits and full breathing apparatus/smoke diver equipment, as well as by fire fighters not\ninvolved in smoke diving who are wearing fire-fighter outfits and helmets.\nThe engineering specification of the firefighter’s outfit in the FSS Code (Chapter 3, Section 2.1.1) requires that the personal\nequipment shall consist of protective clothing made of material designed to protect the skin from heat radiating from the fire\nand from burns and scalding by steam.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":61,"source_page_end":61,"raw_source_text":"Are firemen’s outfits including their equipment, two-way portable radiotelephone apparatus for\nfire-fighter’s communication and breathing apparatus in good condition, fit for purpose and available\nfor instant use? (V & M)\nGuide to Inspection\nEach firefighting team shall be equipped with portable two-way radiotelephones for the purposes of communication. The\nefficient use of these radios shall not be inhibited by the use of any firefighting equipment, including the firefighter’s outfit.\nTo be fit for purpose a firefighter wearing a fireman’s outfit and Breathing Apparatus must be able to communicate clearly\nand without restriction with the Command and Control team.\nWhen possible, the inspector should evaluate the effectiveness of the two-way radio communication equipment provided.\nRecord a Finding if there are insufficient intrinsically safe two-way portable radios for the number of fire teams on the muster\nlist, or if wearing a fireman’s outfit and Breathing Apparatus hinders the firefighter’s ability to operate the radios while\nfighting a fire.\nOne complete fireman’s outfit should include following items:\n> SCBA (self-contained breathing apparatus)\n> Fireman’s suit\n> Fireman’s helmet\n> Fireman’s rubber boots\n> Explosion proof light\nFireproof lifeline combination rope of wire and nylon or hemp rope, complete with safety snap hook. Available in 30, 40 and 50\nmetre lengths.\n> Fire axe\n> Fireman safety belt\n“Compressed air breathing apparatus shall be fitted with an audible alarm and a visual or other device which will alert\nthe user before the volume of the air in the cylinder has been reduced to no less than 200 litres.” This applies to ship’s\nconstructed (keel laid) on or after 1 July 2014. Ships constructed (keel laid) before 1 July 2014 must comply no later than 1\nJuly 2019.\n“An on-board means of recharging breathing apparatus cylinders used during drills shall be provided or a suitable number of\nspare cylinders shall be carried on board to replace those used.” This applies to all ships on or after 1 July 2014.\n“For ships constructed on or after 1 July 2014, a minimum of two two-way portable radiotelephone apparatus for each fire\nparty for fire-fighter’s communication shall be carried on board. These two-way portable radiotelephone apparatuses shall\nbe of an explosion-proof type or intrinsically safe. Ships constructed before 1 July 2014 shall comply with the requirements\nof this paragraph not later than the first safety equipment survey after 1 July 2018.”\n(SOLAS 74, 2020)\nThe two-way portable radio should comply with the IACS UI SC291.\nThe purpose of these fire-fighter radios is to provide a dedicated means of communication between the team of fire fighters\nentering the space and the crew member located outside the space who is assigned to control this team.\nThe two-way portable radio, intended for use by the fire fighters in the Fire Party, should be capable of being used by crew\nmembers wearing full fire fighter suits and full breathing apparatus/smoke diver equipment, as well as by fire fighters not\ninvolved in smoke diving who are wearing fire-fighter outfits and helmets.\nThe engineering specification of the firefighter’s outfit in the FSS Code (Chapter 3, Section 2.1.1) requires that the personal\nequipment shall consist of protective clothing made of material designed to protect the skin from heat radiating from the fire\nand from burns and scalding by steam.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.31","internal_question_no":"04A.031","question_sort_key":4103100.073,"question_text":"Is the operation and maintenance of the breathing apparatus air recharging system (where fitted) incorporated in the ship’s safety management manual, and has the annual air quality check for breathing apparatus air recharging systems been carried out?","guide_to_inspection":"Annual testing should be carried out to ensure the air quality of breathing apparatus air recharging systems.\n(MSC/Circ.1432, Revised Guidelines for the Maintenance and Inspection of Fire-Protection Systems and Appliances, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":62,"source_page_end":62,"raw_source_text":"Is the operation and maintenance of the breathing apparatus air recharging system (where fitted)\nincorporated in the ship’s safety management manual, and has the annual air quality check for breathing\napparatus air recharging systems been carried out? (V & M)\nGuide to Inspection\nAnnual testing should be carried out to ensure the air quality of breathing apparatus air recharging systems.\n(MSC/Circ.1432, Revised Guidelines for the Maintenance and Inspection of Fire-Protection Systems and Appliances, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.32","internal_question_no":"04A.032","question_sort_key":4103200.074,"question_text":"Are records available to show that Emergency Escape Breathing Devices (EEBDs) in the accommodation and engine room are being inspected, in good condition and are available for instant use?","guide_to_inspection":"The minimum number of EEBDs to be kept within accommodation spaces should be:\nFor cargo ships: two (2) EEBDs and one (1) spare EEBD.\nIn machinery spaces for category A containing internal combustion machinery used for main propulsion, EEBDs should be\npositioned as follows:\n1. One (1) EEBD in the engine control room, if located within the machinery space.\n2. One (1) EEBD in workshop areas. If there is, however, a direct access to an escape way from the workshop, an EEBD is not\nrequired; and\n3. one (1) EEBD on each deck or platform level near the escape ladder constituting the second means of escape from the\nmachinery space (the other means being an enclosed escape trunk or watertight door at the lower level of the space).\nAlternatively, different number or location may be determined by the Administration taking into consideration the layout and\ndimensions or the normal manning of the space.\nFor machinery spaces of category A other than those containing internal combustion machinery used for main propulsion, one\n(1) EEBD should, as a minimum, be provided on each deck or platform level near the escape ladder constituting the second\nmeans of escape from the space (the other means being an enclosed escape trunk or watertight door at the lower level of the\nspace).\nFor other machinery spaces, the number and location of EEBDs are to be determined by the Administration.\n(MSC/Circ.1081, Unified Interpretations of SOLAS\nRegulations II-2/13.3.4 and II-1/13.4.3, 2003)\nThe EEBD should be maintained in accordance with the manufacturer’s instructions.\nSpare EEBDs should be kept on board.\nMaintenance requirements, manufacturer’s trademark and serial number, shelf life with accompanying manufacture date and\nname of approving authority should be printed on each EEBD.\nTraining in the use of the EEBD should be considered as a part of basic safety training.\nAll EEBD training units should be clearly marked.\nPersonnel should be trained to immediately don an EEBD prior to exiting a space when the atmosphere becomes life\nthreatening. This is necessary due to the possibility of encountering smoke during escape. Such training should be\naccomplished by scheduling routine escape drills for crew members working in the engineering or machinery spaces.\n(MSC/Circ.849, Guidelines for The Performance, Location,\nUse and Care of Emergency Escape Breathing Devices (EEBDs), 1998)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":62,"source_page_end":62,"raw_source_text":"Are records available to show that Emergency Escape Breathing Devices (EEBDs) in the accommodation\nand engine room are being inspected, in good condition and are available for instant use? (V & M)\nGuide to Inspection\nThe minimum number of EEBDs to be kept within accommodation spaces should be:\nFor cargo ships: two (2) EEBDs and one (1) spare EEBD.\nIn machinery spaces for category A containing internal combustion machinery used for main propulsion, EEBDs should be\npositioned as follows:\n1. One (1) EEBD in the engine control room, if located within the machinery space.\n2. One (1) EEBD in workshop areas. If there is, however, a direct access to an escape way from the workshop, an EEBD is not\nrequired; and\n3. one (1) EEBD on each deck or platform level near the escape ladder constituting the second means of escape from the\nmachinery space (the other means being an enclosed escape trunk or watertight door at the lower level of the space).\nAlternatively, different number or location may be determined by the Administration taking into consideration the layout and\ndimensions or the normal manning of the space.\nFor machinery spaces of category A other than those containing internal combustion machinery used for main propulsion, one\n(1) EEBD should, as a minimum, be provided on each deck or platform level near the escape ladder constituting the second\nmeans of escape from the space (the other means being an enclosed escape trunk or watertight door at the lower level of the\nspace).\nFor other machinery spaces, the number and location of EEBDs are to be determined by the Administration.\n(MSC/Circ.1081, Unified Interpretations of SOLAS\nRegulations II-2/13.3.4 and II-1/13.4.3, 2003)\nThe EEBD should be maintained in accordance with the manufacturer’s instructions.\nSpare EEBDs should be kept on board.\nMaintenance requirements, manufacturer’s trademark and serial number, shelf life with accompanying manufacture date and\nname of approving authority should be printed on each EEBD.\nTraining in the use of the EEBD should be considered as a part of basic safety training.\nAll EEBD training units should be clearly marked.\nPersonnel should be trained to immediately don an EEBD prior to exiting a space when the atmosphere becomes life\nthreatening. This is necessary due to the possibility of encountering smoke during escape. Such training should be\naccomplished by scheduling routine escape drills for crew members working in the engineering or machinery spaces.\n(MSC/Circ.849, Guidelines for The Performance, Location,\nUse and Care of Emergency Escape Breathing Devices (EEBDs), 1998)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.33","internal_question_no":"04A.033","question_sort_key":4103300.075,"question_text":"Are ventilation fire dampers clearly marked with open/close positions and space served and is there evidence of regular testing and maintenance?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":62,"source_page_end":62,"raw_source_text":"Are ventilation fire dampers clearly marked with open/close positions and space served and is there evidence\nof regular testing and maintenance? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.34","internal_question_no":"04A.034","question_sort_key":4103400.076,"question_text":"Are Material Safety Data Sheets (MSDS) for all bunkers, chemicals, paint, corrosive, and toxic materials available, and are all crew familiar with their contents?","guide_to_inspection":"It is essential before use of any hazardous substance that the manufacturer’s safety data sheet (SDS) is referred to, to select\nappropriate personal protective equipment (PPE) and working methods.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nAll stores on board where hazardous or toxic substances are kept, such as paint and chemical stores, shall have readily\naccessible MSDS.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":63,"source_page_end":63,"raw_source_text":"Are Material Safety Data Sheets (MSDS) for all bunkers, chemicals, paint, corrosive, and toxic materials\navailable, and are all crew familiar with their contents? (V)\nGuide to Inspection\nIt is essential before use of any hazardous substance that the manufacturer’s safety data sheet (SDS) is referred to, to select\nappropriate personal protective equipment (PPE) and working methods.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nAll stores on board where hazardous or toxic substances are kept, such as paint and chemical stores, shall have readily\naccessible MSDS.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.35","internal_question_no":"04A.035","question_sort_key":4103500.077,"question_text":"Is a safe means of access to the vessel being provided?","guide_to_inspection":"Accommodation Ladders:\nI n accordance with their design, Accommodation ladders should, if reasonably practicable be firmly landed on the wharf.\nThe use of an accommodation ladder in a suspended or “floating” condition poses elevated safety risks to personnel and\nmitigating measures must be taken to reduce these to as low as reasonably practicable.\nLanded Accommodation Ladders:\nIf a suitable surface is available, the accommodation ladder should be firmly landed. The following requirements apply:\n> Risk Assessment: Conduct a specific risk assessment to identify hazards and establish appropriate controls.\n> Location: The means of embarkation and disembarkation should be sited clear of obstructions and working areas and\nshould not be placed where cargo or other suspended loads may pass overhead.\n> Supervised Use: Ensure the means of access arrangement is attended whenever personnel are using it.\n> Emergency Equipment: Position a lifebuoy with a buoyant line and self-igniting light in the vicinity of the embarkation\nand disembarkation arrangement for immediate deployment in case of emergency.\n> Lighting: Provide clear illumination of the ladder arrangement and immediate approaches during hours of darkness.\n> Marking: The accommodation ladder should be clearly marked at each end with a plate showing the restrictions on the\nsafe operation and loading, including the maximum and minimum permitted design angles of inclination, design load,\nmaximum load on bottom end plate, etc.\n> Records of Testing: Records must be available to confirm static load and operational testing have taken place on the\nwinch and accommodation ladder.\n> Maintenance: The accommodation ladder, winch, wires and connection to the deck shall be inspected and maintained\nin suitable condition for their intended purpose, taking into account any restrictions related to safe loading. All wires\nused to support the means of embarkation and disembarkation shall be maintained as specified in SOLAS III/20.4.\n> Angle: Accommodation ladders should not be used at an angle greater than 55° from the horizontal, unless designed\nand constructed for use at angles greater than these and marked as such.\n> Wires: Accommodation ladder wires are to be inspected periodically, and renewed when necessary due to deterioration\nof the wires or at intervals of not more than 5 years, whichever is the earlier; wire rope certificates should be kept\navailable. When the accommodation ladder is landed on the wharf, the wires should not obstruct use of the walking\nsurface.\n> Side rails, stanchions and ropes: During use, the side rails, stanchions and ropes should be maintained fully rigged with\nside ropes taut.\n> Safety Net: A safety net should be rigged in way of the accommodation ladder, from the top outboard rail, under the\nladder, to either the top inboard rail or preferably to the ship’s side rail covering the gap between the ladder and the\nships side or where impracticable to the top inboard rail of the ladder, preferably to the ship’s side covering the gap\nbetween the ladder and the ship side or where impracticable to the top inboard rail of the ladder. In either case, the net\nshould be sufficiently taut so as to provide cushioning to any person or object falling on to it.\n> Botto m Platform: The bottom platform should be maintained in a horizontal condition.\nSuspended/Floated Accommodation Ladders:\nWhere the berth design and/or terminal/berth regulations prevent the ladder from being landed, this limitation should\nbe communicated to the Master prior to berthing. In such cases, a brow/gangway may be rigged in conjunction with the\naccommodation ladder, between the ladder’s bottom platform and the wharf surface; where this cannot be safely achieved,\nuse of a suspended offshore accommodation ladder in conjunction with launch access should be considered.\nIn addition to the above requirements, the following risk mitigation measures should be implemented:\n> Risk Assessment: Conduct a specific risk assessment to identify hazards and establish appropriate controls, noting the\nsuspended/floated status of the accommodation ladder and brow.\n> Signage: Display a placard warning of the risks associated with the suspended/floated accommodation ladder and\nbrow and instructing users to proceed one at a time.\n> Inspection of Ladder Pins: Prior to fixing a brow, the pins on the lower platform of the accommodation ladder are to be\ninspected to confirm they are secure and in good condition.\n> Certification: A brow must be inspected and found fit for purpose, and the Master must hold the relevant approval\ncertificate for ship’s equipment, or have sighted the relevant approval certificate if the brow is shore-supplied.\n> Brow Rigging: A brow must be rigged such that one end is firmly located and secured on the horizontal lower platform\nof the accommodation ladder, and the other end is firmly located on the wharf surface. Any angle of inclination limits are\nto be complied with.\n> Side rails, stanchions and ropes: Where not fixed the side rails, stanchions and ropes for a brow and an accommodation\nladder should be maintained fully rigged with side ropes taut.\n> Safety Net: Rigging of the safety net should incorporate any brow arrangement.\n> Emergency Equipment: Where offshore boarding by launch is utilised a lifejacket must be worn.\n> Compliance: A suspended/floated accommodation ladder or brow are not to be used if flag State, port State, local or\nother regulations require otherwise.\nMasters’ attention is drawn to MSC.1/Circ.1331, SOLAS II-1/3-9, and SOLAS III/20.4.\nInspectors should not record a finding when an accommodation ladder complies with the above specified provisions and is\nlanded or when a vessel uses a suspended or floating accommodation ladder, provided that all relevant mitigation measures\nhave been properly implemented and verified.\nThe RightShip best practice & lessons learned for Safe Means of Access must be taken in to account when rigging a safe\nmeans of access. Please click here","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":63,"source_page_end":64,"raw_source_text":"Is a safe means of access to the vessel being provided? (V)\nGuide to Inspection\nAccommodation Ladders:\nI n accordance with their design, Accommodation ladders should, if reasonably practicable be firmly landed on the wharf.\nThe use of an accommodation ladder in a suspended or “floating” condition poses elevated safety risks to personnel and\nmitigating measures must be taken to reduce these to as low as reasonably practicable.\nLanded Accommodation Ladders:\nIf a suitable surface is available, the accommodation ladder should be firmly landed. The following requirements apply:\n> Risk Assessment: Conduct a specific risk assessment to identify hazards and establish appropriate controls.\n> Location: The means of embarkation and disembarkation should be sited clear of obstructions and working areas and\nshould not be placed where cargo or other suspended loads may pass overhead.\n> Supervised Use: Ensure the means of access arrangement is attended whenever personnel are using it.\n> Emergency Equipment: Position a lifebuoy with a buoyant line and self-igniting light in the vicinity of the embarkation\nand disembarkation arrangement for immediate deployment in case of emergency.\n> Lighting: Provide clear illumination of the ladder arrangement and immediate approaches during hours of darkness.\n> Marking: The accommodation ladder should be clearly marked at each end with a plate showing the restrictions on the\nsafe operation and loading, including the maximum and minimum permitted design angles of inclination, design load,\nmaximum load on bottom end plate, etc.\n> Records of Testing: Records must be available to confirm static load and operational testing have taken place on the\nwinch and accommodation ladder.\n> Maintenance: The accommodation ladder, winch, wires and connection to the deck shall be inspected and maintained\nin suitable condition for their intended purpose, taking into account any restrictions related to safe loading. All wires\nused to support the means of embarkation and disembarkation shall be maintained as specified in SOLAS III/20.4.\n> Angle: Accommodation ladders should not be used at an angle greater than 55° from the horizontal, unless designed\nand constructed for use at angles greater than these and marked as such.\n> Wires: Accommodation ladder wires are to be inspected periodically, and renewed when necessary due to deterioration\nof the wires or at intervals of not more than 5 years, whichever is the earlier; wire rope certificates should be kept\navailable. When the accommodation ladder is landed on the wharf, the wires should not obstruct use of the walking\nsurface.\n> Side rails, stanchions and ropes: During use, the side rails, stanchions and ropes should be maintained fully rigged with\nside ropes taut.\n> Safety Net: A safety net should be rigged in way of the accommodation ladder, from the top outboard rail, under the\nladder, to either the top inboard rail or preferably to the ship’s side rail covering the gap between the ladder and the\nships side or where impracticable to the top inboard rail of the ladder, preferably to the ship’s side covering the gap\nbetween the ladder and the ship side or where impracticable to the top inboard rail of the ladder. In either case, the net\nshould be sufficiently taut so as to provide cushioning to any person or object falling on to it.\n> Botto m Platform: The bottom platform should be maintained in a horizontal condition.\nSuspended/Floated Accommodation Ladders:\nWhere the berth design and/or terminal/berth regulations prevent the ladder from being landed, this limitation should\nbe communicated to the Master prior to berthing. In such cases, a brow/gangway may be rigged in conjunction with the\naccommodation ladder, between the ladder’s bottom platform and the wharf surface; where this cannot be safely achieved,\nuse of a suspended offshore accommodation ladder in conjunction with launch access should be considered.\nIn addition to the above requirements, the following risk mitigation measures should be implemented:\n> Risk Assessment: Conduct a specific risk assessment to identify hazards and establish appropriate controls, noting the\nsuspended/floated status of the accommodation ladder and brow.\n> Signage: Display a placard warning of the risks associated with the suspended/floated accommodation ladder and\nbrow and instructing users to proceed one at a time.\n> Inspection of Ladder Pins: Prior to fixing a brow, the pins on the lower platform of the accommodation ladder are to be\ninspected to confirm they are secure and in good condition.\n> Certification: A brow must be inspected and found fit for purpose, and the Master must hold the relevant approval\ncertificate for ship’s equipment, or have sighted the relevant approval certificate if the brow is shore-supplied.\n> Brow Rigging: A brow must be rigged such that one end is firmly located and secured on the horizontal lower platform\nof the accommodation ladder, and the other end is firmly located on the wharf surface. Any angle of inclination limits are\nto be complied with.\n> Side rails, stanchions and ropes: Where not fixed the side rails, stanchions and ropes for a brow and an accommodation\nladder should be maintained fully rigged with side ropes taut.\n> Safety Net: Rigging of the safety net should incorporate any brow arrangement.\n> Emergency Equipment: Where offshore boarding by launch is utilised a lifejacket must be worn.\n> Compliance: A suspended/floated accommodation ladder or brow are not to be used if flag State, port State, local or\nother regulations require otherwise.\nMasters’ attention is drawn to MSC.1/Circ.1331, SOLAS II-1/3-9, and SOLAS III/20.4.\nInspectors should not record a finding when an accommodation ladder complies with the above specified provisions and is\nlanded or when a vessel uses a suspended or floating accommodation ladder, provided that all relevant mitigation measures\nhave been properly implemented and verified.\nThe RightShip best practice & lessons learned for Safe Means of Access must be taken in to account when rigging a safe\nmeans of access. Please click here","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.36","internal_question_no":"04A.036","question_sort_key":4103600.078,"question_text":"Are accommodation ladders and gangways maintained in good condition, marked clearly, and inspected regularly","guide_to_inspection":"Record a Finding If the maintenance and inspection of the accommodation ladder turn table and its pin were not included in the PMS\nAccommodation ladders and gangways, including associate winches and fittings, should be properly maintained, and\ninspected at appropriate intervals as required by SOLAS regulation III/20.7.2, in accordance with manufacturers’ instructions.\nAdditional checks should be made each time an accommodation ladder or gangway is rigged, looking out for signs of\ndistortion, cracks, and corrosion. Close examination for possible corrosion should be carried out, especially when an\naluminium accommodation ladder/gangway has fittings made of mild steel.\nBent stanchions should be replaced or repaired and guard ropes should be inspected for wear and renewed where necessary.\nMoving parts should be free to turn and should be greased as appropriate.\nThe lifting equipment should be inspected, tested, and maintained paying careful attention to the condition of the hoist wire.\nThe wires used to support the means of embarkation and disembarkation should be renewed when necessary, as required by\nSOLAS regulation II-1/3-9.\nArrangements should also be made to examine the underside of gangways and accommodation ladders at regular intervals.\nAll inspections, maintenance work and repairs of accommodation ladders and gangways should be recorded to provide an\naccurate history for each appliance. The information to be recorded appropriately on board should include the date of the\nmost recent inspection, the name of the person or body who carried out that inspection, the due date for the next inspection\nand the dates of renewal of wires used to support the embarkation and disembarkation arrangement.\nWinch:\nDuring annual surveys required by SOLAS regulations I/7 and I/8, the following items should be examined for satisfactory condition:\n> Brake mechanism including condition of brake pads and band brake, if fitted.\n> Remote control system; and\n> Power supply system (motor).\nAt every five-yearly survey, the winch should be operationally tested with the specified maximum operational load of the\naccommodation ladder.\nMarking:\nEach accommodation ladder or gangway should be clearly marked at each end with a plate showing the restrictions on\nthe safe operation and loading, including the maximum and minimum permitted design angles of inclination, design load,\nmaximum load on bottom end plate, etc. Where the maximum operational load is less than the design load, it should also be\nshown on the marking plate.\n(MSC.1/Circ.1331, Guidelines for Construction, Installation, Maintenance and\nInspection/Survey of Means of Embarkation and Disembarkation, 2009)\nThe certificate (s) for a five-year load test of an accommodation ladder should be kept on board, and the load test should\nbe performed within the stipulated time period. A manufacturer’s certificate for a fall wire in service should be provided, as\nwell as confirmation that accommodation ladder fall wires have been replaced within the last five years. The date of fall wire\nrenewal should be stencilled in the vicinity of the fall wire winch.\nAll wires used to support the means of embarkation and disembarkation shall be maintained and inspected with special\nregard to the areas passing through sheaves. The falls should be ‘renewed when necessary due to the deterioration of the\nfalls or at intervals of not more than five years, whichever is the earlier as per SOLAS III/20.4, SOLAS II-1/3- and MSC.1/\nCirc.1206.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":64,"source_page_end":65,"raw_source_text":"Are accommodation ladders and gangways maintained in good condition, marked clearly,\nand inspected regularly (V)\nGuide to Inspection\nRecord a Finding If the maintenance and inspection of the accommodation ladder turn table and its pin were not included in the PMS\nAccommodation ladders and gangways, including associate winches and fittings, should be properly maintained, and\ninspected at appropriate intervals as required by SOLAS regulation III/20.7.2, in accordance with manufacturers’ instructions.\nAdditional checks should be made each time an accommodation ladder or gangway is rigged, looking out for signs of\ndistortion, cracks, and corrosion. Close examination for possible corrosion should be carried out, especially when an\naluminium accommodation ladder/gangway has fittings made of mild steel.\nBent stanchions should be replaced or repaired and guard ropes should be inspected for wear and renewed where necessary.\nMoving parts should be free to turn and should be greased as appropriate.\nThe lifting equipment should be inspected, tested, and maintained paying careful attention to the condition of the hoist wire.\nThe wires used to support the means of embarkation and disembarkation should be renewed when necessary, as required by\nSOLAS regulation II-1/3-9.\nArrangements should also be made to examine the underside of gangways and accommodation ladders at regular intervals.\nAll inspections, maintenance work and repairs of accommodation ladders and gangways should be recorded to provide an\naccurate history for each appliance. The information to be recorded appropriately on board should include the date of the\nmost recent inspection, the name of the person or body who carried out that inspection, the due date for the next inspection\nand the dates of renewal of wires used to support the embarkation and disembarkation arrangement.\nWinch:\nDuring annual surveys required by SOLAS regulations I/7 and I/8, the following items should be examined for satisfactory condition:\n> Brake mechanism including condition of brake pads and band brake, if fitted.\n> Remote control system; and\n> Power supply system (motor).\nAt every five-yearly survey, the winch should be operationally tested with the specified maximum operational load of the\naccommodation ladder.\nMarking:\nEach accommodation ladder or gangway should be clearly marked at each end with a plate showing the restrictions on\nthe safe operation and loading, including the maximum and minimum permitted design angles of inclination, design load,\nmaximum load on bottom end plate, etc. Where the maximum operational load is less than the design load, it should also be\nshown on the marking plate.\n(MSC.1/Circ.1331, Guidelines for Construction, Installation, Maintenance and\nInspection/Survey of Means of Embarkation and Disembarkation, 2009)\nThe certificate (s) for a five-year load test of an accommodation ladder should be kept on board, and the load test should\nbe performed within the stipulated time period. A manufacturer’s certificate for a fall wire in service should be provided, as\nwell as confirmation that accommodation ladder fall wires have been replaced within the last five years. The date of fall wire\nrenewal should be stencilled in the vicinity of the fall wire winch.\nAll wires used to support the means of embarkation and disembarkation shall be maintained and inspected with special\nregard to the areas passing through sheaves. The falls should be ‘renewed when necessary due to the deterioration of the\nfalls or at intervals of not more than five years, whichever is the earlier as per SOLAS III/20.4, SOLAS II-1/3- and MSC.1/\nCirc.1206.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.37","internal_question_no":"04A.037","question_sort_key":4103700.079,"question_text":"Are pilot ladders used for pilot transfer in good condition, and inspected regularly, clearly identified with tags or with permanent marking and are maintenance records available and, are crew members capable of demonstrating proper rigging of the pilot-ladder arrangement?","guide_to_inspection":"Counterfeit pilot ladders and certificates pose a serious safety risk and remain a significant industry concern. To mitigate this risk,\nship managers should adopt one or both of the following measures:\nMaintain Accurate Records:\nEnsure that the Record of Approved Safety Equipment, where it includes pilot transfer arrangements, is updated to accurately reflect\nthe details specified in the relevant form.\nVerify Certificate Authenticity:\nShip managers should establish and implement a formal procurement procedure that requires direct verification of the pilot ladder\ncertificate’s authenticity with the issuing authority (e.g., manufacturer, classification society) prior to accepting delivery. Objective\nevidence of this verification, such as email confirmation, or an verifiable digital certificate, should be retained onboard and kept\nreadily available for audit or future compliance checks.\nComments should also specify whether the ladder steps are made of hardwood, aluminum, or composite materials.\nIf a pilot ladder is made of a material other than hardwood, it should possess equivalent strength, stiffness, and durability to the\nsatisfaction of the Administration.( IMO Res 10459(27))\nWhen plastic materials are used in the construction of a pilot ladder, ISO 877 provides guidance with regards to testing for both\noriginal tensile and original impact strength.\n( Pilot ladder manual 2024)\nExpected service life of the pilot ladder, which may be less than 30 months, especially on ladders with mechanically placed metal\nclamps that prevent inspection of the side ropes. If a pilot ladder’s service life exceeds 30 months, the test specified in section 6.6 of\nISO standard 799-2021 should be conducted.\nPersonnel responsible for rigging and inspecting pilot ladders shall receive periodic training in the inspection requirements,\nregulations and standards associated with pilot ladders and their use.\nWhere other arrangements or equipment are essential for use in conjunction with a pilot ladder, those arrangements or equipment\nshall be included in such training. This requirement may be fulfilled by the use of an onboard computer-based training module.\n(BS ISO 799-2:2021 Ships and marine technology. Pilot ladders.\nMaintenance, use, survey, and inspection, 2021)\nThe vessel’s manager should follow the international standards for inspecting the pilot ladder, such as ISO799-2:2021 Annex\nA. This standard provides checklists for pre-use, post-use, three-monthly and annual inspections. RightShip recommends this\npractice to ensure the safety and quality of the pilot ladder.\nAll pilot ladders used for pilot transfer shall be clearly identified with tags or other permanent marking so as to enable identification\nof each appliance for the purposes of survey, inspection and record keeping. A record shall be kept on the ship as to the date the\nidentified ladder is placed into service and any repairs effected.\n(SOLAS 74, 2020)\nThe top of the pilot ladder should be secured to the approved fixing point and not to handrails. Ladder steps or spacers should not\nbe rigged in a position in which they are taking the weight of the ladder.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nWhen utilising a combination pilot ladder arrangement, it is necessary to secure both the pilot ladder and accommodation ladder to\nthe ship’s side. CLICK HERE to access the IMO Circular MSC.1/Circ.1428, which illustrates the pilot transfer arrangements required\nby SOLAS V/23.\nSOLAS Chapter V, Regulation 23, necessitates securing the lower platform of the accommodation ladder to the ship’s side. This is\nto ensure that the lower end of the accommodation ladder and the lower platform are held firmly against the ship’s side.\nIf the accommodation ladder is not secured to the ship’s structure, it is possible for the combination ladder to swing violently and\nuncontrollably with a pendulum motion.\nWhen a combination arrangement is used for pilot access, means shall be provided to secure the pilot ladder and manropes to the\nship’s side at a point of nominally 1.5 m above the bottom platform of the accommodation ladder.\n(SOLAS 2020)\n(The Pilot ladder Manual 2024)\nThere are several methods available to ensure multiple securing points:\n> Fastening to fixed lashing points built into the ship’s hull.\n> Use of movable magnetic or pneumatic fixing equipment.\nThe easiest way to secure the ladder is the use of two strong (at least 2 x 24 kN) manila ropes directly attached to each side rope of\nthe pilot ladder, by means of a rolling hitch knot.\nAny pilot ladders not in use should be clearly identified and tagged.\nThe requirements in SOLAS V/23, deal with the standards for equipment installed and arrangements for pilot transfers on ships on\nor after 1 July 2012. The standards adopted by the IMO can be found in IMO Resolution A.1045(27) “Pilot transfer arrangements”.\nSOLAS V/23.2.3 additionally states that a pilot ladder shall be certified by the manufacturer as complying with V/23 or “with an\ninternational standard acceptable to the Organization” and ref and refers to ISO 799:2004 Ships and marine technology.\nCounterfeit pilot ladders and certificates:\nA counterfeit pilot ladder is a ladder that purports to be a genuine, approved product from a manufacturer certified by an approved\nbody in the manufacture of pilot ladders to a certified standard, but is not.\nAt a minimum, a pilot ladder certificate should have:\n1. The name and address of the manufacturer\n2. The serial number\n3 . The model and length of the ladder\n4. The date of manufacture\n5. The standards, resolutions and regulations to which the ladder complies (eg. SOLAS 74 Reg. V/23 & SOLAS 74 Reg. X/3, IMO\nRes. A.1045(27), IMO Res. MSC/Circ. 1428, ISO 799:1 2019)\n6. The certifying authority\nRightShip strongly encourages the vessel’s manager to verify the authenticity of the pilot ladder certificate by contacting the\nrelevant certification body. It is important to keep a record of such verification on board for future reference.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":65,"source_page_end":66,"raw_source_text":"Are pilot ladders used for pilot transfer in good condition, and inspected regularly, clearly identified with tags\nor with permanent marking and are maintenance records available and, are crew members capable of\ndemonstrating proper rigging of the pilot-ladder arrangement?(V)\nGuide to Inspection\nCounterfeit pilot ladders and certificates pose a serious safety risk and remain a significant industry concern. To mitigate this risk,\nship managers should adopt one or both of the following measures:\nMaintain Accurate Records:\nEnsure that the Record of Approved Safety Equipment, where it includes pilot transfer arrangements, is updated to accurately reflect\nthe details specified in the relevant form.\nVerify Certificate Authenticity:\nShip managers should establish and implement a formal procurement procedure that requires direct verification of the pilot ladder\ncertificate’s authenticity with the issuing authority (e.g., manufacturer, classification society) prior to accepting delivery. Objective\nevidence of this verification, such as email confirmation, or an verifiable digital certificate, should be retained onboard and kept\nreadily available for audit or future compliance checks.\nComments should also specify whether the ladder steps are made of hardwood, aluminum, or composite materials.\nIf a pilot ladder is made of a material other than hardwood, it should possess equivalent strength, stiffness, and durability to the\nsatisfaction of the Administration.( IMO Res 10459(27))\nWhen plastic materials are used in the construction of a pilot ladder, ISO 877 provides guidance with regards to testing for both\noriginal tensile and original impact strength.\n( Pilot ladder manual 2024)\nExpected service life of the pilot ladder, which may be less than 30 months, especially on ladders with mechanically placed metal\nclamps that prevent inspection of the side ropes. If a pilot ladder’s service life exceeds 30 months, the test specified in section 6.6 of\nISO standard 799-2021 should be conducted.\nPersonnel responsible for rigging and inspecting pilot ladders shall receive periodic training in the inspection requirements,\nregulations and standards associated with pilot ladders and their use.\nWhere other arrangements or equipment are essential for use in conjunction with a pilot ladder, those arrangements or equipment\nshall be included in such training. This requirement may be fulfilled by the use of an onboard computer-based training module.\n(BS ISO 799-2:2021 Ships and marine technology. Pilot ladders.\nMaintenance, use, survey, and inspection, 2021)\nThe vessel’s manager should follow the international standards for inspecting the pilot ladder, such as ISO799-2:2021 Annex\nA. This standard provides checklists for pre-use, post-use, three-monthly and annual inspections. RightShip recommends this\npractice to ensure the safety and quality of the pilot ladder.\nAll pilot ladders used for pilot transfer shall be clearly identified with tags or other permanent marking so as to enable identification\nof each appliance for the purposes of survey, inspection and record keeping. A record shall be kept on the ship as to the date the\nidentified ladder is placed into service and any repairs effected.\n(SOLAS 74, 2020)\nThe top of the pilot ladder should be secured to the approved fixing point and not to handrails. Ladder steps or spacers should not\nbe rigged in a position in which they are taking the weight of the ladder.\n(Code of Safe Working Practices for Merchant Seafarer’s, 2024)\nWhen utilising a combination pilot ladder arrangement, it is necessary to secure both the pilot ladder and accommodation ladder to\nthe ship’s side. CLICK HERE to access the IMO Circular MSC.1/Circ.1428, which illustrates the pilot transfer arrangements required\nby SOLAS V/23.\nSOLAS Chapter V, Regulation 23, necessitates securing the lower platform of the accommodation ladder to the ship’s side. This is\nto ensure that the lower end of the accommodation ladder and the lower platform are held firmly against the ship’s side.\nIf the accommodation ladder is not secured to the ship’s structure, it is possible for the combination ladder to swing violently and\nuncontrollably with a pendulum motion.\nWhen a combination arrangement is used for pilot access, means shall be provided to secure the pilot ladder and manropes to the\nship’s side at a point of nominally 1.5 m above the bottom platform of the accommodation ladder.\n(SOLAS 2020)\n(The Pilot ladder Manual 2024)\nThere are several methods available to ensure multiple securing points:\n> Fastening to fixed lashing points built into the ship’s hull.\n> Use of movable magnetic or pneumatic fixing equipment.\nThe easiest way to secure the ladder is the use of two strong (at least 2 x 24 kN) manila ropes directly attached to each side rope of\nthe pilot ladder, by means of a rolling hitch knot.\nAny pilot ladders not in use should be clearly identified and tagged.\nThe requirements in SOLAS V/23, deal with the standards for equipment installed and arrangements for pilot transfers on ships on\nor after 1 July 2012. The standards adopted by the IMO can be found in IMO Resolution A.1045(27) “Pilot transfer arrangements”.\nSOLAS V/23.2.3 additionally states that a pilot ladder shall be certified by the manufacturer as complying with V/23 or “with an\ninternational standard acceptable to the Organization” and ref and refers to ISO 799:2004 Ships and marine technology.\nCounterfeit pilot ladders and certificates:\nA counterfeit pilot ladder is a ladder that purports to be a genuine, approved product from a manufacturer certified by an approved\nbody in the manufacture of pilot ladders to a certified standard, but is not.\nAt a minimum, a pilot ladder certificate should have:\n1. The name and address of the manufacturer\n2. The serial number\n3 . The model and length of the ladder\n4. The date of manufacture\n5. The standards, resolutions and regulations to which the ladder complies (eg. SOLAS 74 Reg. V/23 & SOLAS 74 Reg. X/3, IMO\nRes. A.1045(27), IMO Res. MSC/Circ. 1428, ISO 799:1 2019)\n6. The certifying authority\nRightShip strongly encourages the vessel’s manager to verify the authenticity of the pilot ladder certificate by contacting the\nrelevant certification body. It is important to keep a record of such verification on board for future reference.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.38","internal_question_no":"04A.038","question_sort_key":4103800.08,"question_text":"Has the vessel been provided with ship-specific fire safety and SOLAS training manuals and operational booklets?","guide_to_inspection":"Fire Safety training manual: A training manual shall be written in the working language of the ship and shall be provided in each\ncrew mess room and recreation room or in each crew cabin. The manual shall contain the instructions and information required\nin regulation II-2/15.2.3.4. Part of such information may be provided in the form of audio-visual aids in lieu of the manual.\n(SOLAS 74, 2020)\nSOLAS training manual: Specific training manuals shall be provided in each crew mess room and recreation room, or in each\ncabin and shall contain instructions and information on the life-saving appliances provided in the ship. It shall also contain\ninformation on the best methods of survival. The material in the manual shall be in easily understood terms and illustrated\nwhere appropriate.\nThe following when applicable, shall be incorporated into the manual and explained in detail:\n> Donning of lifejackets, immersion suits and anti-exposure suits, as appropriate.\n> Muster at the assigned stations.\n> Boarding, launching, and clearing the survival craft, rescue boats, fast rescue boats, free-fall boats and inflated boats.\n> Method of launching from within the survival craft.\n> Release from launching appliances.\n> Methods and use of devices for protection in launching areas.\n> Illumination in launching areas.\n> Use of all survival equipment.\n> Use of all detection equipment.\n> With the assistance of illustrations, the use of radio lifesaving appliances.\n> Use of sea anchors.\n> Use of engine and accessories.\n> Recovery of the survival craft, rescue boats, fast rescue boats, free-fall boats and inflated boats including stowage and\nsecuring.\n> Hazards of exposure and the need for warm clothing.\n> Best use of the survival craft facilities in order to survive.\n> Methods of retrieval, including the use of helicopter rescue gear (slings, baskets, stretchers), breeches-buoy and shore\nlife-saving apparatus and ship’s line-throwing apparatus; all other functions contained in the muster list and emergency\ninstructions.\nThe fire safety operational booklet shall contain the necessary information and instructions for the safe operation of the ship\nand cargo handling operations in relation to fire safety. The booklet shall be written in the working language of the ship and\nbe provided in each crew mess room and recreation room or in each crew cabin. The booklet may be combined with the fire\nsafety training manuals required in regulation II-2/15.2.3. The booklet may be combined with the fire training manual.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":67,"source_page_end":67,"raw_source_text":"Has the vessel been provided with ship-specific fire safety and SOLAS training manuals and\noperational booklets? (V)\nGuide to Inspection\nFire Safety training manual: A training manual shall be written in the working language of the ship and shall be provided in each\ncrew mess room and recreation room or in each crew cabin. The manual shall contain the instructions and information required\nin regulation II-2/15.2.3.4. Part of such information may be provided in the form of audio-visual aids in lieu of the manual.\n(SOLAS 74, 2020)\nSOLAS training manual: Specific training manuals shall be provided in each crew mess room and recreation room, or in each\ncabin and shall contain instructions and information on the life-saving appliances provided in the ship. It shall also contain\ninformation on the best methods of survival. The material in the manual shall be in easily understood terms and illustrated\nwhere appropriate.\nThe following when applicable, shall be incorporated into the manual and explained in detail:\n> Donning of lifejackets, immersion suits and anti-exposure suits, as appropriate.\n> Muster at the assigned stations.\n> Boarding, launching, and clearing the survival craft, rescue boats, fast rescue boats, free-fall boats and inflated boats.\n> Method of launching from within the survival craft.\n> Release from launching appliances.\n> Methods and use of devices for protection in launching areas.\n> Illumination in launching areas.\n> Use of all survival equipment.\n> Use of all detection equipment.\n> With the assistance of illustrations, the use of radio lifesaving appliances.\n> Use of sea anchors.\n> Use of engine and accessories.\n> Recovery of the survival craft, rescue boats, fast rescue boats, free-fall boats and inflated boats including stowage and\nsecuring.\n> Hazards of exposure and the need for warm clothing.\n> Best use of the survival craft facilities in order to survive.\n> Methods of retrieval, including the use of helicopter rescue gear (slings, baskets, stretchers), breeches-buoy and shore\nlife-saving apparatus and ship’s line-throwing apparatus; all other functions contained in the muster list and emergency\ninstructions.\nThe fire safety operational booklet shall contain the necessary information and instructions for the safe operation of the ship\nand cargo handling operations in relation to fire safety. The booklet shall be written in the working language of the ship and\nbe provided in each crew mess room and recreation room or in each crew cabin. The booklet may be combined with the fire\nsafety training manuals required in regulation II-2/15.2.3. The booklet may be combined with the fire training manual.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.39","internal_question_no":"04A.039","question_sort_key":4103900.081,"question_text":"If the vessel is provided with a helicopter operating area, does the area comply with the requirements of ICS guidelines, and is there a safe access from the hatch cover to deck?","guide_to_inspection":"Record a Finding if a strength confirmation letter from a classification society is not available on board. The inspector shall\nobtain a copy of the strength letter and attach it to the RightShip inspection report under Question 4.37. Additionally, the\ninspector should provide 360-degree photographs of the landing site and access, when practicable.\nIf the helicopter operation area is designated as “Winch Only,” the requirement for a strength confirmation letter does not\napply to the vessel.\nThe construction and usage of inclined ladder(s) for accessing the helicopter operation area may not be possible on a\nnumber of cargo vessels, specially smaller cargo ships. This is due to factors such as the structural design, location of\nfittings, and limited deck space. If that is the situation, the inspector should answer Yes to the question and provide an\nexplanation in the comment area regarding why the vessel was unable to use the inclined ladder(s).\nThe strength of the HLS for the vessel is to be confirmed by the following documents:\n1. Maximum designed load for helicopter landing on HLS as described in the structural drawings such as hatch cover, upper\ndeck, etc.\n2. Strength confirmation letter by HLS designer (shipyard, hatch cover maker, etc.) or the Flag State.\n3. Strength confirmation letter issued by classification society in cases where neither items 1 nor 2 above are available.\nIn order to issue the letter under this paragraph, the structural drawing of the HLS is to be submitted to the classification\nsociety. In addition, fire-fighting equipment for helicopter facilities are required to comply with the “Guide to Helicopter/Ship\nOperations, 5th Edition issued by the International Chamber of Shipping.\nThe access from hatch cover to deck should be a fixed height inclined ladder with fixed handrails and front platform with\noperational load for two persons (150 KG). The steps and platforms should be made of non-slip materials.\nThe Master of a vessel must ensure that any obstacle within the landing or winching area is clearly marked if it does comply\nwith the recommendations for obstacles in the ICS Guide.\n(AMSA Marine Orders Part 57)\nIn addition to the marking arrangements described, the vessel’s manager should ensure that, if possible, a minimum of two\naccess/egress routes to and from the landing area available to ensure that, in the event of an incident on the landing area,\nhelicopter passengers and crew can escape upwind of the incident.\nHandrails exceeding the height limitation set out in section 4.1.2 of the Guide to helicopter/ship operation shall be retractable,\ncollapsible or removed. Such handrails should be painted in a contrasting colour scheme and procedure should be in place to\nretract, collapse or remove them prior to the arrival of the helicopter.\nRed and white strips should be used for marking the position of notifiable objects within either the manoeuvring zone or\nclearing zone that exceed the height limits for those zone(refer figure 4.1 of the ICS Guide to Helicopter/Ship Operations\nEdition 5):\n> Object within the clear zone of heigh exceeding 2.5 cm\n> Objects outside the clear zone but within the manoeuvring zone of height exceeding 25 cm.\nYellow should be used for marking the position of objects beyond the manoeuvring zone to which it is considered appropriate\nto draw the attention of the helicopter pilot. Yellow may also be used to mark objects within manoeuvring zone and clear\nzone below the height limits for either the clear zone(2.5 cm) or the manoeuvring zone(25 cm) and to which it is considered\nappropriate to draw the attention of the helicopter pilot.\n(ICS Guide to Helicopter/Ship Operations Edition 5)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":67,"source_page_end":68,"raw_source_text":"If the vessel is provided with a helicopter operating area, does the area comply with the requirements of\nICS guidelines, and is there a safe access from the hatch cover to deck? (V)\nGuide to Inspection\nRecord a Finding if a strength confirmation letter from a classification society is not available on board. The inspector shall\nobtain a copy of the strength letter and attach it to the RightShip inspection report under Question 4.37. Additionally, the\ninspector should provide 360-degree photographs of the landing site and access, when practicable.\nIf the helicopter operation area is designated as “Winch Only,” the requirement for a strength confirmation letter does not\napply to the vessel.\nThe construction and usage of inclined ladder(s) for accessing the helicopter operation area may not be possible on a\nnumber of cargo vessels, specially smaller cargo ships. This is due to factors such as the structural design, location of\nfittings, and limited deck space. If that is the situation, the inspector should answer Yes to the question and provide an\nexplanation in the comment area regarding why the vessel was unable to use the inclined ladder(s).\nThe strength of the HLS for the vessel is to be confirmed by the following documents:\n1. Maximum designed load for helicopter landing on HLS as described in the structural drawings such as hatch cover, upper\ndeck, etc.\n2. Strength confirmation letter by HLS designer (shipyard, hatch cover maker, etc.) or the Flag State.\n3. Strength confirmation letter issued by classification society in cases where neither items 1 nor 2 above are available.\nIn order to issue the letter under this paragraph, the structural drawing of the HLS is to be submitted to the classification\nsociety. In addition, fire-fighting equipment for helicopter facilities are required to comply with the “Guide to Helicopter/Ship\nOperations, 5th Edition issued by the International Chamber of Shipping.\nThe access from hatch cover to deck should be a fixed height inclined ladder with fixed handrails and front platform with\noperational load for two persons (150 KG). The steps and platforms should be made of non-slip materials.\nThe Master of a vessel must ensure that any obstacle within the landing or winching area is clearly marked if it does comply\nwith the recommendations for obstacles in the ICS Guide.\n(AMSA Marine Orders Part 57)\nIn addition to the marking arrangements described, the vessel’s manager should ensure that, if possible, a minimum of two\naccess/egress routes to and from the landing area available to ensure that, in the event of an incident on the landing area,\nhelicopter passengers and crew can escape upwind of the incident.\nHandrails exceeding the height limitation set out in section 4.1.2 of the Guide to helicopter/ship operation shall be retractable,\ncollapsible or removed. Such handrails should be painted in a contrasting colour scheme and procedure should be in place to\nretract, collapse or remove them prior to the arrival of the helicopter.\nRed and white strips should be used for marking the position of notifiable objects within either the manoeuvring zone or\nclearing zone that exceed the height limits for those zone(refer figure 4.1 of the ICS Guide to Helicopter/Ship Operations\nEdition 5):\n> Object within the clear zone of heigh exceeding 2.5 cm\n> Objects outside the clear zone but within the manoeuvring zone of height exceeding 25 cm.\nYellow should be used for marking the position of objects beyond the manoeuvring zone to which it is considered appropriate\nto draw the attention of the helicopter pilot. Yellow may also be used to mark objects within manoeuvring zone and clear\nzone below the height limits for either the clear zone(2.5 cm) or the manoeuvring zone(25 cm) and to which it is considered\nappropriate to draw the attention of the helicopter pilot.\n(ICS Guide to Helicopter/Ship Operations Edition 5)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.40","internal_question_no":"04A.040","question_sort_key":4104000.082,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":68,"source_page_end":68,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.41","internal_question_no":"04A.041","question_sort_key":4104100.083,"question_text":"Are the crew familiar with the helicopter operation at sea, and are records available to show that the proper communication, shipboard helicopter safety checklist and specific risk assessment conducted prior to helicopter operation?","guide_to_inspection":"The inventory of helicopter equipment shall be in compliance with section 9.3 of the record of approved Ship Safety Equipment.\nEvidence of communication between helicopter and vessel’s bridge team, shipboard safety checklist for helicopter operations,\nspecific risk assessment (as per appendix B of Guide to Helicopter/Ship operation) should be available and reviewed by inspector.\nHelicopter operations are commonly used for embarkation and disembarkation of Pilot and medical evacuation in emergency\nsituations. The helicopter operation is a complicated, high-risk operation. This operation demands accuracy, training, and\nclearly established procedures. The officers and crew members associated with these operations should show a high level of\nsituational awareness and good seamanship.\nFor additional information, reference should be made to the Rightship best practice & lessons learned for Helicopter\nOperations High Potential Near Miss Incidents. Please download the document via this link.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":68,"source_page_end":68,"raw_source_text":"Are the crew familiar with the helicopter operation at sea, and are records available to show that the\nproper communication, shipboard helicopter safety checklist and specific risk assessment conducted prior\nto helicopter operation? (V)\nGuide to Inspection\nThe inventory of helicopter equipment shall be in compliance with section 9.3 of the record of approved Ship Safety Equipment.\nEvidence of communication between helicopter and vessel’s bridge team, shipboard safety checklist for helicopter operations,\nspecific risk assessment (as per appendix B of Guide to Helicopter/Ship operation) should be available and reviewed by inspector.\nHelicopter operations are commonly used for embarkation and disembarkation of Pilot and medical evacuation in emergency\nsituations. The helicopter operation is a complicated, high-risk operation. This operation demands accuracy, training, and\nclearly established procedures. The officers and crew members associated with these operations should show a high level of\nsituational awareness and good seamanship.\nFor additional information, reference should be made to the Rightship best practice & lessons learned for Helicopter\nOperations High Potential Near Miss Incidents. Please download the document via this link.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.42","internal_question_no":"04A.042","question_sort_key":4104200.084,"question_text":"Are the lifebuoys, related equipment, and pyrotechnics in good working order?","guide_to_inspection":"Cargo ships shall carry not less than the following numbers of lifebuoys:\n> Under 100 metres in length - 8\n> Between 100 metres and under 150 metres - 10\n> Between 150 metres and under 200 metres - 12\n> 200 metres and over – 14\nAt least one lifebuoy on each side of the ship shall be fitted with a buoyant line, equal in length to not less than twice the height\nat which it is stowed above the waterline in the lightest seagoing condition, or 30 metres, whichever is the greater.\nNot less than one half of the total number of lifebuoys shall be provided with self-igniting lights; Not less than two of these shall\nalso be provided with lifebuoy self-activating smoke signals capable of quick release from the navigating bridge; Lifebuoys\nwith lights and those with lights and smoke signals shall be distributed equally on both sides of the ship and shall not be the\nlifebuoys provided with lifelines.\n12 rocket parachute flares must be carried and stored on or near the navigation bridge. There shall be a line throwing appliance\nthat complies with the requirements of Section 7.1 of the Code. The officer of the watch shall have readily available an illustrated\ntable describing the life-saving signals. The line throwing apparatus should be immediately available for use. The line and\nrockets should not be separated when stowed. Self-contained rocket line throwing appliances are frequently dismantled prior to\ntransport to the vessel. Inspectors should verify that all equipment has been reassembled and rockets are properly positioned\nfor immediate use. Containers, brackets, racks, and other similar stowage locations for life-saving equipment shall be labelled in\naccordance with IMO Resolution A.760(18) with symbols indicating the devices stowed in that location for that purpose. If that\nlocation is used to store more than one device, the number of devices must also be indicated.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":69,"source_page_end":69,"raw_source_text":"Are the lifebuoys, related equipment, and pyrotechnics in good working order?\nGuide to Inspection\nCargo ships shall carry not less than the following numbers of lifebuoys:\n> Under 100 metres in length - 8\n> Between 100 metres and under 150 metres - 10\n> Between 150 metres and under 200 metres - 12\n> 200 metres and over – 14\nAt least one lifebuoy on each side of the ship shall be fitted with a buoyant line, equal in length to not less than twice the height\nat which it is stowed above the waterline in the lightest seagoing condition, or 30 metres, whichever is the greater.\nNot less than one half of the total number of lifebuoys shall be provided with self-igniting lights; Not less than two of these shall\nalso be provided with lifebuoy self-activating smoke signals capable of quick release from the navigating bridge; Lifebuoys\nwith lights and those with lights and smoke signals shall be distributed equally on both sides of the ship and shall not be the\nlifebuoys provided with lifelines.\n12 rocket parachute flares must be carried and stored on or near the navigation bridge. There shall be a line throwing appliance\nthat complies with the requirements of Section 7.1 of the Code. The officer of the watch shall have readily available an illustrated\ntable describing the life-saving signals. The line throwing apparatus should be immediately available for use. The line and\nrockets should not be separated when stowed. Self-contained rocket line throwing appliances are frequently dismantled prior to\ntransport to the vessel. Inspectors should verify that all equipment has been reassembled and rockets are properly positioned\nfor immediate use. Containers, brackets, racks, and other similar stowage locations for life-saving equipment shall be labelled in\naccordance with IMO Resolution A.760(18) with symbols indicating the devices stowed in that location for that purpose. If that\nlocation is used to store more than one device, the number of devices must also be indicated.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.43","internal_question_no":"04A.043","question_sort_key":4104300.085,"question_text":"Are adequate familiarization procedures in place that cover the personal safety and professional obligations of new personnel and personnel transferred to a new assignment, and are documents available to confirm effective familiarization?","guide_to_inspection":"The company should establish procedures to ensure that new personnel and personnel transferred to new assignments\nrelated to safety and protection of the environment are given proper familiarization with their duties.\nInstructions which are essential to be provided prior to sailing should be identified, documented and given.\n(ISM code and guidelines on the implementation of the ISM code, 2018)\nDeck officer familiarization with navigation equipment should be delivered one-on-one using a common language using the\nBridge Procedures Guide’s (BPG) checklist C2.3 and C2.4. Familiarization should include all bridge equipment and procedures\nrelevant to the roles and responsibilities of each bridge team member.\n(Bridge Procedures Guide, 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":69,"source_page_end":69,"raw_source_text":"Are adequate familiarization procedures in place that cover the personal safety and professional obligations\nof new personnel and personnel transferred to a new assignment, and are documents available to confirm\neffective familiarization?(V)\nGuide to Inspection\nThe company should establish procedures to ensure that new personnel and personnel transferred to new assignments\nrelated to safety and protection of the environment are given proper familiarization with their duties.\nInstructions which are essential to be provided prior to sailing should be identified, documented and given.\n(ISM code and guidelines on the implementation of the ISM code, 2018)\nDeck officer familiarization with navigation equipment should be delivered one-on-one using a common language using the\nBridge Procedures Guide’s (BPG) checklist C2.3 and C2.4. Familiarization should include all bridge equipment and procedures\nrelevant to the roles and responsibilities of each bridge team member.\n(Bridge Procedures Guide, 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"04A","section_number":4,"section_letter":"A","section_title":"ISM System","printed_question_no":"4.44","internal_question_no":"04A.044","question_sort_key":4104400.086,"question_text":"Does the vessel manager have documented procedures in place to control stevedore activities onboard by identifying potential hazards and implementing appropriate mitigation measures?","guide_to_inspection":"> Stevedore Safety in Cargo Operations\n>\n> Stevedores engaged in cargo operations are exposed to a variety of hazards, particularly when adequate supervision\nis not maintained onboard. These risks may arise from the nature of the cargo, unfamiliarity with shipboard safety\nprocedures, or the working environment itself.\n> Common hazards include:\n> Entry into confined or enclosed spaces\n> Slips, trips, and falls\n> Machinery and equipment-related risks\n> Exposure to hazardous chemicals\n> Fire hazards\n> Without adequate training and awareness, stevedores may inadvertently engage in unsafe practices, significantly\nincreasing the risk of serious incidents or fatalities.\n> The safety of stevedores during cargo operations primarily rests with the stevedore company which must ensure its\npersonnel are :\n- Properly trained and competent in their roles\n- Familiar with shipboard procedures and safety protocols\n- Equipped with appropriate personal protective equipment (PPE)\n- Fully aware of operational hazards and risk controls\n- A designated company representative must be present onboard to supervise stevedores throughout the operation.\nThis includes actively monitoring their activities, identifying unsafe behaviours, and intervening immediately when necessary.\nAdditionally, vessel managers are responsible for ensuring the designated stevedore representative receives a pre-operation\nsafety briefing who is responsible to brief stevedores in their working language at each shift. The ship-shore safety checklist\nin accordance with BLU Code including item 13 to be shared with the stevedore representative.\nPre-Work Briefing / Toolbox Meeting\nA concise pre-work briefing or toolbox meeting should be conducted between the Master (or their designated representative)\nand the stevedore designated representative . This meeting should:\n> Outline relevant safety procedures\n> Emphasise the consequences of non-compliance\n> Reinforce the vessel’s Stop-Work Authority, including the right to suspend operations if unsafe conditions arise\n> The briefing should be documented in the cargo logbook or, where appropriate, included in the ship-shore safety\nchecklist.\nAccess Control & Enclosed Space Management\nStrict access control to cargo holds and enclosed spaces is critical. The vessel should:\n> Lock and secure all access points to confined spaces, including cargo holds not in use\n> Implement controlled entry procedures, including:\n-Physical barricading\n-Clear signage\n-Padlocking of restricted areas\nThe Master retains ultimate authority over access approvals and should ensure full compliance with enclosed space entry\nprotocols throughout cargo operations.\nAll enclosed space entries by shore personnel should include:\n> Shore personnel should be informed of the hazards associated with enclosed spaces that may exist on board vessels.\nBoth the general and specific requirements outlined in MSC.1/Circ.581 (110) should be carefully considered and\nadhered to.\n> Verified atmosphere testing\n> Permit-to-enter signed by a ship’s officer\n> Appropriate caution signage and physical barriers\nStop-Work Authority\nThe vessel manager should reinforce the crew’s authority to stop work immediately if unsafe conditions, equipment, or\nbehaviours are observed. This includes:\n> Immediate suspension of cargo operations upon detection of unsafe practices\n> Documentation of all unsafe conditions and behaviours\n> Resumption of operations only after corrective actions have been implemented by the stevedores\nThe vessel manager should clearly define:\n> Conditions that warrant activation of stop-work authority\n> Criteria for safely resuming operations\nSupervision and Risk Assessment\nStevedore operations should be monitored by shipboard personnel and the stevedore company to ensure safety and\ncompliance. Any unauthorized access or entry into restricted areas should be immediately challenged and reported through\nthe appropriate channels.\nRisk assessments should be:\n> Specific to the vessel and its operations\n> Developed by both the ship and the stevedore company and exchanged prior to commencement of cargo operations\n> Discussed during pre-work briefings or toolbox meetings\nThese assessments should address operational hazards associated with cargo handling methods, equipment usage, and\nstevedore work practices, and should be reviewed and discussed during the Pre-Work Briefing or Toolbox Meeting.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":69,"source_page_end":70,"raw_source_text":"Does the vessel manager have documented procedures in place to control stevedore activities onboard by\nidentifying potential hazards and implementing appropriate mitigation measures?(V)\nGuide to Inspection\n> Stevedore Safety in Cargo Operations\n>\n> Stevedores engaged in cargo operations are exposed to a variety of hazards, particularly when adequate supervision\nis not maintained onboard. These risks may arise from the nature of the cargo, unfamiliarity with shipboard safety\nprocedures, or the working environment itself.\n> Common hazards include:\n> Entry into confined or enclosed spaces\n> Slips, trips, and falls\n> Machinery and equipment-related risks\n> Exposure to hazardous chemicals\n> Fire hazards\n> Without adequate training and awareness, stevedores may inadvertently engage in unsafe practices, significantly\nincreasing the risk of serious incidents or fatalities.\n> The safety of stevedores during cargo operations primarily rests with the stevedore company which must ensure its\npersonnel are :\n- Properly trained and competent in their roles\n- Familiar with shipboard procedures and safety protocols\n- Equipped with appropriate personal protective equipment (PPE)\n- Fully aware of operational hazards and risk controls\n- A designated company representative must be present onboard to supervise stevedores throughout the operation.\nThis includes actively monitoring their activities, identifying unsafe behaviours, and intervening immediately when necessary.\nAdditionally, vessel managers are responsible for ensuring the designated stevedore representative receives a pre-operation\nsafety briefing who is responsible to brief stevedores in their working language at each shift. The ship-shore safety checklist\nin accordance with BLU Code including item 13 to be shared with the stevedore representative.\nPre-Work Briefing / Toolbox Meeting\nA concise pre-work briefing or toolbox meeting should be conducted between the Master (or their designated representative)\nand the stevedore designated representative . This meeting should:\n> Outline relevant safety procedures\n> Emphasise the consequences of non-compliance\n> Reinforce the vessel’s Stop-Work Authority, including the right to suspend operations if unsafe conditions arise\n> The briefing should be documented in the cargo logbook or, where appropriate, included in the ship-shore safety\nchecklist.\nAccess Control & Enclosed Space Management\nStrict access control to cargo holds and enclosed spaces is critical. The vessel should:\n> Lock and secure all access points to confined spaces, including cargo holds not in use\n> Implement controlled entry procedures, including:\n-Physical barricading\n-Clear signage\n-Padlocking of restricted areas\nThe Master retains ultimate authority over access approvals and should ensure full compliance with enclosed space entry\nprotocols throughout cargo operations.\nAll enclosed space entries by shore personnel should include:\n> Shore personnel should be informed of the hazards associated with enclosed spaces that may exist on board vessels.\nBoth the general and specific requirements outlined in MSC.1/Circ.581 (110) should be carefully considered and\nadhered to.\n> Verified atmosphere testing\n> Permit-to-enter signed by a ship’s officer\n> Appropriate caution signage and physical barriers\nStop-Work Authority\nThe vessel manager should reinforce the crew’s authority to stop work immediately if unsafe conditions, equipment, or\nbehaviours are observed. This includes:\n> Immediate suspension of cargo operations upon detection of unsafe practices\n> Documentation of all unsafe conditions and behaviours\n> Resumption of operations only after corrective actions have been implemented by the stevedores\nThe vessel manager should clearly define:\n> Conditions that warrant activation of stop-work authority\n> Criteria for safely resuming operations\nSupervision and Risk Assessment\nStevedore operations should be monitored by shipboard personnel and the stevedore company to ensure safety and\ncompliance. Any unauthorized access or entry into restricted areas should be immediately challenged and reported through\nthe appropriate channels.\nRisk assessments should be:\n> Specific to the vessel and its operations\n> Developed by both the ship and the stevedore company and exchanged prior to commencement of cargo operations\n> Discussed during pre-work briefings or toolbox meetings\nThese assessments should address operational hazards associated with cargo handling methods, equipment usage, and\nstevedore work practices, and should be reviewed and discussed during the Pre-Work Briefing or Toolbox Meeting.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.1","internal_question_no":"05A.001","question_sort_key":5100100.087,"question_text":"Is the Oil Record Book (Part 1) completed correctly?","guide_to_inspection":"The Flag Administration may permit the use of an electronic oil record book as an alternative substitute of the traditional\npaper ORB. However, Flag approval should be available on board and verified by the inspector.\nNon-automatic starting of discharge overboard via 15 ppm equipment, transfer, or disposal otherwise of bilge water which\nhas accumulated in machinery spaces should be recorded in section D.\nPumping of bilge water from engine-room bilge wells to a tank listed under item 3.3 in the Supplement to the IOPPC should be\nrecorded in section D 15.3.\nAutomatic starting of discharge overboard, transfer or disposal otherwise of bilge water which has accumulated in machinery\nspaces should be recorded in section E. The automatic starting systems will be activated by float switches in bilge wells or bilge\nholding tanks. This system is rarely installed in the machinery space of dry cargo vessels.\nThe condition of oil filtering equipment and oil content meter or stopping device, including the alarm and automatic stopping\ndevices when defective should be recorded in section F. A code ‘I’ entry should also be made indicating that the overboard valve\nwas sealed shut due to non-working oil filtering equipment or oil content meter.\nOn the date when the system is functional again, a new entry, using code F should be made. A code ‘I’ entry should also be made\nindicating that the overboard valve was unsealed since the operation of the oil filtering equipment or oil content meter has been\nrestored.\nAccidental or other exceptional discharges of oil should be recorded in section G.\nBunkering of fuel or bulk lubricating oil should be recorded in section H. Separate entries are required for each grade of fuel oil and\nlubricating oil respectively to ensure transparency. This entry is not required if lubricating oil are delivered on board in packaged\nform (55-gallon drum, etc.).\nVoluntary declaration of quantities retained in bilge water holding tanks (ref MEPC.1/Circ.640) should be record weekly in section I.\n(MEPC.1/Circ.736/Rev.2, Guidance for the Recording of Operations\nin the Oil Record Book Part I- Machinery Space Operations (All Ships), 2011)\n“When disposal of engine-room oil water or sludge to a shore reception facility has taken place, the entry in the Oil record Book shall\nbe made accurately and in consistency with the shore reception facility receipt.”","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":71,"source_page_end":71,"raw_source_text":"Is the Oil Record Book (Part 1) completed correctly? (V)\nGuide to Inspection\nThe Flag Administration may permit the use of an electronic oil record book as an alternative substitute of the traditional\npaper ORB. However, Flag approval should be available on board and verified by the inspector.\nNon-automatic starting of discharge overboard via 15 ppm equipment, transfer, or disposal otherwise of bilge water which\nhas accumulated in machinery spaces should be recorded in section D.\nPumping of bilge water from engine-room bilge wells to a tank listed under item 3.3 in the Supplement to the IOPPC should be\nrecorded in section D 15.3.\nAutomatic starting of discharge overboard, transfer or disposal otherwise of bilge water which has accumulated in machinery\nspaces should be recorded in section E. The automatic starting systems will be activated by float switches in bilge wells or bilge\nholding tanks. This system is rarely installed in the machinery space of dry cargo vessels.\nThe condition of oil filtering equipment and oil content meter or stopping device, including the alarm and automatic stopping\ndevices when defective should be recorded in section F. A code ‘I’ entry should also be made indicating that the overboard valve\nwas sealed shut due to non-working oil filtering equipment or oil content meter.\nOn the date when the system is functional again, a new entry, using code F should be made. A code ‘I’ entry should also be made\nindicating that the overboard valve was unsealed since the operation of the oil filtering equipment or oil content meter has been\nrestored.\nAccidental or other exceptional discharges of oil should be recorded in section G.\nBunkering of fuel or bulk lubricating oil should be recorded in section H. Separate entries are required for each grade of fuel oil and\nlubricating oil respectively to ensure transparency. This entry is not required if lubricating oil are delivered on board in packaged\nform (55-gallon drum, etc.).\nVoluntary declaration of quantities retained in bilge water holding tanks (ref MEPC.1/Circ.640) should be record weekly in section I.\n(MEPC.1/Circ.736/Rev.2, Guidance for the Recording of Operations\nin the Oil Record Book Part I- Machinery Space Operations (All Ships), 2011)\n“When disposal of engine-room oil water or sludge to a shore reception facility has taken place, the entry in the Oil record Book shall\nbe made accurately and in consistency with the shore reception facility receipt.”","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.2","internal_question_no":"05A.002","question_sort_key":5100200.088,"question_text":"Is an approved MARPOL Shipboard Oil Pollution Emergency Plan (SOPEP) available, and up to date and are ship’s personnel familiar with their duties?","guide_to_inspection":"Every ship other than an oil tanker of 400 gross tonnage and above shall carry on board a shipboard oil-pollution emergency\nplan approved by the Administration.\nSuch a plan shall be prepared based on guidelines developed by the Organisation and written in the working language of the\nMaster and officers. The plan shall consist at least of:\n> The procedure to be followed by the Master or other persons having charge of the ship to report an oil pollution incident\n> The list of authorities or persons to be contacted in the event of an oil pollution incident\n> A detailed description of the action to be taken immediately by persons on board to reduce or control the discharge of\noil following the incident\n> The procedures and point of contact on the ship for coordinating shipboard action in combating the pollution with\nnational and local authorities\n> Description of equipment, its location, a plan for deployment and specific crewmember duties for handling small spills, and\n> An up-to-date IMO Coastal Contact List.\nThe SOPEP must be re-approved after a change of management. The list of national operational contact points is issued\nelectronically on a quarterly basis on the 31 January, 30 April, 31 July and 31 October at www.imo.org.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":71,"source_page_end":71,"raw_source_text":"Is an approved MARPOL Shipboard Oil Pollution Emergency Plan (SOPEP) available, and up to date and\nare ship’s personnel familiar with their duties? (V)\nGuide to Inspection\nEvery ship other than an oil tanker of 400 gross tonnage and above shall carry on board a shipboard oil-pollution emergency\nplan approved by the Administration.\nSuch a plan shall be prepared based on guidelines developed by the Organisation and written in the working language of the\nMaster and officers. The plan shall consist at least of:\n> The procedure to be followed by the Master or other persons having charge of the ship to report an oil pollution incident\n> The list of authorities or persons to be contacted in the event of an oil pollution incident\n> A detailed description of the action to be taken immediately by persons on board to reduce or control the discharge of\noil following the incident\n> The procedures and point of contact on the ship for coordinating shipboard action in combating the pollution with\nnational and local authorities\n> Description of equipment, its location, a plan for deployment and specific crewmember duties for handling small spills, and\n> An up-to-date IMO Coastal Contact List.\nThe SOPEP must be re-approved after a change of management. The list of national operational contact points is issued\nelectronically on a quarterly basis on the 31 January, 30 April, 31 July and 31 October at www.imo.org.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.3","internal_question_no":"05A.003","question_sort_key":5100300.089,"question_text":"Are the ship’s personnel aware of the requirements of MARPOL Annex V with respect to the disposal of operational waste and cargo residues from ships?","guide_to_inspection":"Operational waste means all solid waste (including slurries) not covered by other Annexes that are collected on board during normal\nmaintenance or operation of a ship or used for cargo stowage and handling.\nOperational waste also includes cleaning agents and additives contained in cargo holds and external wash water.\nOperational waste does not include grey water, bilge water, or other similar discharge essential to the operation of a ship, taking into\naccount the guidelines developed by the Organisation.\nCargo residues means the remnants of any cargo which are not covered by other Annexes and which remain on the deck or in holds\nfollowing loading and unloading; including loading and unloading excess or spillage, whether in wet or dry condition or entrained in\nwash water; but does not include cargo dust remaining on the deck after sweeping or dust on the external surface of the ship.\n(MARPOL, 2017)\nThe SKULD P&I club information paper “Guidance on disposal of cargo residues in line with MARPOL Annex V “provides further\ninformation.\nDeck scuppers should be plugged during cargo operations involving residues that are harmful to the marine environment.\nVessel managers should establish procedures to ensure the integrity of deck containment is maintained. This includes the proper use\nof drain valves where fitted and ensuring controlled drainage of accumulated water from the deck during cargo operations.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":72,"source_page_end":72,"raw_source_text":"Are the ship’s personnel aware of the requirements of MARPOL Annex V with respect to the disposal of\noperational waste and cargo residues from ships? (V)\nGuide to Inspection\nOperational waste means all solid waste (including slurries) not covered by other Annexes that are collected on board during normal\nmaintenance or operation of a ship or used for cargo stowage and handling.\nOperational waste also includes cleaning agents and additives contained in cargo holds and external wash water.\nOperational waste does not include grey water, bilge water, or other similar discharge essential to the operation of a ship, taking into\naccount the guidelines developed by the Organisation.\nCargo residues means the remnants of any cargo which are not covered by other Annexes and which remain on the deck or in holds\nfollowing loading and unloading; including loading and unloading excess or spillage, whether in wet or dry condition or entrained in\nwash water; but does not include cargo dust remaining on the deck after sweeping or dust on the external surface of the ship.\n(MARPOL, 2017)\nThe SKULD P&I club information paper “Guidance on disposal of cargo residues in line with MARPOL Annex V “provides further\ninformation.\nDeck scuppers should be plugged during cargo operations involving residues that are harmful to the marine environment.\nVessel managers should establish procedures to ensure the integrity of deck containment is maintained. This includes the proper use\nof drain valves where fitted and ensuring controlled drainage of accumulated water from the deck during cargo operations.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.4","internal_question_no":"05A.004","question_sort_key":5100400.09,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":72,"source_page_end":72,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.5","internal_question_no":"05A.005","question_sort_key":5100500.091,"question_text":"Is the vessel free from any visible bulkhead leakage?","guide_to_inspection":"The examples of bulkheads are:\n> The engine room forward bulkhead at its intersection with the topside tank structure in the aftermost cargo hold.\n> The side shell plating of the cargo hold side structure.\n> Side shell plating in the foremost cargo hold.\n> The stool shelf plates of the transverse bulkheads in the cargo hold.\n> The transverse bulkheads at the topside tank connection, in the cargo hold.\n> The vertical corrugations of transverse bulkheads in the cargo hold.\n> The corrugated bulkheads at the intersection of the shredder plates in the cargo holds.\n> Any fuel tank bulkheads within the machinery space","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":72,"source_page_end":72,"raw_source_text":"Is the vessel free from any visible bulkhead leakage? (V)\nGuide to Inspection\nThe examples of bulkheads are:\n> The engine room forward bulkhead at its intersection with the topside tank structure in the aftermost cargo hold.\n> The side shell plating of the cargo hold side structure.\n> Side shell plating in the foremost cargo hold.\n> The stool shelf plates of the transverse bulkheads in the cargo hold.\n> The transverse bulkheads at the topside tank connection, in the cargo hold.\n> The vertical corrugations of transverse bulkheads in the cargo hold.\n> The corrugated bulkheads at the intersection of the shredder plates in the cargo holds.\n> Any fuel tank bulkheads within the machinery space","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.6","internal_question_no":"05A.006","question_sort_key":5100600.092,"question_text":"Are the cargo hold bilge pumping systems and bilge arrangements appropriately set, in good order and tested?","guide_to_inspection":"Bilge wells, including bilge covers, strum boxes; and bilge well valves, including non-return valves, should be in a clean and sound\ncondition.\nNon-return valves must be checked to ensure they are fully operational. Overhaul of non-return valves at regular intervals should\nbe incorporated into the planned maintenance system. Inspection and testing of these non-return valves should be incorporated in\nthe pre-loading checks of the holds. The presence of previous cargo residues and/or scale around the valve’s seat may prevent the\ncorrect operation of the non-return valve.\nBilge lines should be blown back to confirm the effectiveness of the valves regularly.\nBilge high-level alarms should be tested regularly. Records of testing of alarm systems should be retained on board.\n(Bulk Cargoes-Hold Preparation and Cleaning, 2011)\nWhen the cargo hold bilge system is not in use, all valves should be effectively shut and measures should in place to ensure that\nthey remain shut i.e. visible signs.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":72,"source_page_end":72,"raw_source_text":"Are the cargo hold bilge pumping systems and bilge arrangements appropriately set, in good\norder and tested? (V)\nGuide to Inspection\nBilge wells, including bilge covers, strum boxes; and bilge well valves, including non-return valves, should be in a clean and sound\ncondition.\nNon-return valves must be checked to ensure they are fully operational. Overhaul of non-return valves at regular intervals should\nbe incorporated into the planned maintenance system. Inspection and testing of these non-return valves should be incorporated in\nthe pre-loading checks of the holds. The presence of previous cargo residues and/or scale around the valve’s seat may prevent the\ncorrect operation of the non-return valve.\nBilge lines should be blown back to confirm the effectiveness of the valves regularly.\nBilge high-level alarms should be tested regularly. Records of testing of alarm systems should be retained on board.\n(Bulk Cargoes-Hold Preparation and Cleaning, 2011)\nWhen the cargo hold bilge system is not in use, all valves should be effectively shut and measures should in place to ensure that\nthey remain shut i.e. visible signs.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.7","internal_question_no":"05A.007","question_sort_key":5100700.093,"question_text":"Is the sounding of cargo hold bilge, ballast tanks, chain lockers, pipe ducts and other void spaces regularly performed for accumulations of water, or alternative evidence of regular monitoring?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":73,"source_page_end":73,"raw_source_text":"Is the sounding of cargo hold bilge, ballast tanks, chain lockers, pipe ducts and other void spaces regularly\nperformed for accumulations of water, or alternative evidence of regular monitoring? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.8","internal_question_no":"05A.008","question_sort_key":5100800.094,"question_text":"Are suitable containment arrangements in place around the hydraulic components of deck machinery?","guide_to_inspection":"The hydraulic component can include hatch cover rams and remote-control stand, cranes, winches, windlass, piping, and\nhoses.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":73,"source_page_end":73,"raw_source_text":"Are suitable containment arrangements in place around the hydraulic components of deck machinery? (V)\nGuide to Inspection\nThe hydraulic component can include hatch cover rams and remote-control stand, cranes, winches, windlass, piping, and\nhoses.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.9","internal_question_no":"05A.009","question_sort_key":5100900.095,"question_text":"Are the emergency arrangements to pump out the spaces forward of the collision bulkhead in the event of flooding in good order, and are these arrangements prominently marked?","guide_to_inspection":"Water level detection and alarm system is to be located on the navigation bridge and be capable of detecting water ingress\nat all cargo holds and spaces and ballast tank forward of collision bulkhead. In general, Fore Peak Tank, Bosun’s Store,\nForecastle Space excluding chain lockers are considered as these spaces. The systems is to be a type being approved and\nto be supplied with electrical power from two independent supplies and failure of the primary electrical power supply is\nidentified by an alarm.\n(SOLAS 74 2020)\nThe vessel manager should develop vessel-specific procedures to pump out the spaces forward of the collision bulkhead in\nthe event of flooding, including guidance on:\n> The use of the pumps/eductors connected to the systems, their direct suctions, and overboard valves.\n> The marking of system valves and controls to ensure correct operation and avoid accidental opening.\n> The vessel-specific instructions for pumping out the spaces forward of the collision bulkhead in an emergency may be\nincluded as part of the vessel emergency response plan for forecastle space flooding.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":73,"source_page_end":73,"raw_source_text":"Are the emergency arrangements to pump out the spaces forward of the collision bulkhead in the event of\nflooding in good order, and are these arrangements prominently marked? (V)\nGuide to Inspection\nWater level detection and alarm system is to be located on the navigation bridge and be capable of detecting water ingress\nat all cargo holds and spaces and ballast tank forward of collision bulkhead. In general, Fore Peak Tank, Bosun’s Store,\nForecastle Space excluding chain lockers are considered as these spaces. The systems is to be a type being approved and\nto be supplied with electrical power from two independent supplies and failure of the primary electrical power supply is\nidentified by an alarm.\n(SOLAS 74 2020)\nThe vessel manager should develop vessel-specific procedures to pump out the spaces forward of the collision bulkhead in\nthe event of flooding, including guidance on:\n> The use of the pumps/eductors connected to the systems, their direct suctions, and overboard valves.\n> The marking of system valves and controls to ensure correct operation and avoid accidental opening.\n> The vessel-specific instructions for pumping out the spaces forward of the collision bulkhead in an emergency may be\nincluded as part of the vessel emergency response plan for forecastle space flooding.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.10","internal_question_no":"05A.010","question_sort_key":5101000.096,"question_text":"Are the master and officers familiar with the approved Ballast Water Management Plan, was the ballast water treatment system maintained as per the manufacturer’s recommendations, and is the record-keeping of ballast water operations in the ballast water record book completed correctly?","guide_to_inspection":"The Ballast Water Management Plan (BWMP) is the document that details the procedure for the discharge of ballast water\nin accordance with regulation D-1 (exchange), and/or regulation D-2 (treatment). Conducting ballast water discharge in\naccordance with the BWMP ensures compliance with regulations D-1 or D-2.\nBy September 2024, all ships must confirm conform to the D-2 standard.\nAll ships are required to carry:\n> A ship specific BWMP\n> A Ballast Water Record Book (BWRB)\n> An International Ballast Water Management Certificate (IBWMC)\nThe BWMP is approved by the ship’s flag state and should set out a particular and realistic set of measures to be followed by\nthe crew. These should include the following procedures:\n> Best practices are in place to ensure the BWMS is not disabled or malfunctioning due to mechanical or electrical faults\nthat are easily preventable;\n> Verify the next port of discharge and place into IMO or United States Coast Guard (USCG) mode accordingly;\n> Ensure that all valve position are verified before the start of each ballast operation;\n> All maintenance work is performed inline with the PMS;\n> All consumables (reagents, disinfectants, chemicals, etc.) and critical spare parts are readily available; and\n> Ensure that all troubleshooting and mitigation measures are followed as outlined in the original equipment\nmanufacturer’s instructions.\nThe ship-specific and crew familarisation program should cover:\n> Maintenance of the system, including checklists and schedules for maintaining the system’s optimal condition,\nincluding:\n- Inspection, cleaning, and calibration; and\n- Maintaining adequate spare parts on board, as well as active substances and neutralisers on board, if applicable.\n> Troubleshooting and mitigation where best practices should be established for investigating and resolving common/\ncritical BWMS technical malfunctions that may arise;\n> Record keeping; and\n> The procedure for notifying the port state that they will receive ballast water discharge impacted by failure of\nmalfunction of the BWMS.\nFor record keeping, the following actions requires a note to be made in the BWRB:\n> When ballast water is taken onboard;\n> When ballast water is discharged into the sea\n> Whenever ballast water is exchanged into the sea\n> Whenever ballast water is exchanged, circulated and treated for ballast water management purposes;\n> Uptake or discharge of ballast water from/to a port-based or reception facility\n> Accidental discharge/ingress or other exceptional uptake or discharge of ballast water;\n> Failure and malfunction of the BWMS; and\n> Ballast tank cleaning/flushing, removal and disposal of sediments\nThe duties of the officer in charge of ballast water operations must be specified in the ship’s BWMP.\nThe officer in charge must fill in and sign every BMRB entry and the master should sign every full page.\nShould the BWMS fail, the shipowner/manager should be contacted before bypassing the ballast water treatment system.\nThe ship will need to demonstrate that any bypass of the system will not be a risk to the environment and should only be\nused as a last resort.\n( Engine Room Procedures Guide 2024)\nBallast Water Biosecurity Risks\nAn Active Substance (AS) is defined as ‘a substance or organism, including a virus or a fungus, that has a general or specific\naction on or against harmful aquatic organisms and pathogens’.\nBWMS that use Active Substances (electro-chlorination & chemical-based)\nRepeated ‘low TRO’ alarms during uptake: The Total Residual Oxidant (TRO) sensor is a critical component of a properly\ninstalled BWMS as it measures if ballast water is treated within the system design limits. Repeated ‘low TRO’ or similar\nalarms during uptake may indicate that the ballast water has not been effectively treated due to an insufficient dose or\ngeneration of Active Substance (AS). If ballast water is treated with an AS at a concentration below the lower alarm limit of\nthe system, an increased level of inspection may apply.\n‘High TRO’ alarms during discharge: This alarm could indicate a problem with neutralisation. If the AS in the ballast water\nis not properly neutralised, the ballast water may cause marine pollution. Commonly encountered issues include seized\nmetering pumps, insufficient or incorrectly mixed neutraliser in the neutraliser tank, blocked TRO sensor pipes, expired TRO\nreagents, and incorrectly arranged valves.\n‘TRO Communication’ alarm: During uptake, TRO production by the electrolyser or dosage from the chemical tank is linked\nto the values obtained by the TRO sensor. If the sensor is not properly reporting the AS concentration to the BWMS, then\nthe treatment may not be effective. Further analysis of the error code on the TRO unit could be required. Common problems\ninclude intake valves not opened, intake lines blocked, dirty cuvette, expired reagents, or seized TRO pumps.\nBWMS that use ultra-violet (UV) light\nThese systems rely on UV light to inactivate or kill organisms in the ballast water and often treat on uptake and discharge.\nThe systems use multiple sensors for UV intensity, temperature, water turbidity, and water flow to maintain effective\ntreatment.\nAlarms indicate that the system may not be treating the ballast water effectively. Continually operating when there are\nrepeated alarms for low light intensity, high filter differential pressure, low water flow, or high temperature may result in a\ndetailed inspection and a direction to stop discharge.\n( AUS Gov- Department of Agriculture,Fisheries and Forestry 2025)\nThe TRO sensor measures the amount of free chlorine or chlorine compounds present in the ballast water after it has been\ntreated by the Ballast Water Treatment System . The TRO sensor is used to evaluate the efficiency of the treatment process.\nThe TRO level indicates how effective the treatment has been in killing harmful organisms and pathogens. If the TRO is\noperating outside the permitted tolerance levels, it may indicate that the treatment has not been effective. The result could\nmean that the ballast water may still contain harmful organisms or there is too much chlorine (Cl2) in the ballast water.\nThe TRO sensor should be maintained and calibrated as per the manufacturer’s recommendations.\nAll ships with an approved BWMP should maintain record-keeping of ballast water operations in the BWRB in accordance\nwith guidance BWM.2/Circ.80. They should also apply the codes A to H, together with the specific item number for different\nballast water operations specified in MEPC.369(80).\nIf the approved electronic record books are provided and the hard copy record book is replaced by an electronic one, a ship-\nspecific declaration must be carried on board. This declaration should confirm that the installation of the electronic system\ndesigned to record entries in accordance with the BWM Convention meets the requirements of the IMO guidelines.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":73,"source_page_end":74,"raw_source_text":"Are the master and officers familiar with the approved Ballast Water Management Plan, was the ballast water\ntreatment system maintained as per the manufacturer’s recommendations, and is the record-keeping of ballast\nwater operations in the ballast water record book completed correctly? (V)\nGuide to Inspection\nThe Ballast Water Management Plan (BWMP) is the document that details the procedure for the discharge of ballast water\nin accordance with regulation D-1 (exchange), and/or regulation D-2 (treatment). Conducting ballast water discharge in\naccordance with the BWMP ensures compliance with regulations D-1 or D-2.\nBy September 2024, all ships must confirm conform to the D-2 standard.\nAll ships are required to carry:\n> A ship specific BWMP\n> A Ballast Water Record Book (BWRB)\n> An International Ballast Water Management Certificate (IBWMC)\nThe BWMP is approved by the ship’s flag state and should set out a particular and realistic set of measures to be followed by\nthe crew. These should include the following procedures:\n> Best practices are in place to ensure the BWMS is not disabled or malfunctioning due to mechanical or electrical faults\nthat are easily preventable;\n> Verify the next port of discharge and place into IMO or United States Coast Guard (USCG) mode accordingly;\n> Ensure that all valve position are verified before the start of each ballast operation;\n> All maintenance work is performed inline with the PMS;\n> All consumables (reagents, disinfectants, chemicals, etc.) and critical spare parts are readily available; and\n> Ensure that all troubleshooting and mitigation measures are followed as outlined in the original equipment\nmanufacturer’s instructions.\nThe ship-specific and crew familarisation program should cover:\n> Maintenance of the system, including checklists and schedules for maintaining the system’s optimal condition,\nincluding:\n- Inspection, cleaning, and calibration; and\n- Maintaining adequate spare parts on board, as well as active substances and neutralisers on board, if applicable.\n> Troubleshooting and mitigation where best practices should be established for investigating and resolving common/\ncritical BWMS technical malfunctions that may arise;\n> Record keeping; and\n> The procedure for notifying the port state that they will receive ballast water discharge impacted by failure of\nmalfunction of the BWMS.\nFor record keeping, the following actions requires a note to be made in the BWRB:\n> When ballast water is taken onboard;\n> When ballast water is discharged into the sea\n> Whenever ballast water is exchanged into the sea\n> Whenever ballast water is exchanged, circulated and treated for ballast water management purposes;\n> Uptake or discharge of ballast water from/to a port-based or reception facility\n> Accidental discharge/ingress or other exceptional uptake or discharge of ballast water;\n> Failure and malfunction of the BWMS; and\n> Ballast tank cleaning/flushing, removal and disposal of sediments\nThe duties of the officer in charge of ballast water operations must be specified in the ship’s BWMP.\nThe officer in charge must fill in and sign every BMRB entry and the master should sign every full page.\nShould the BWMS fail, the shipowner/manager should be contacted before bypassing the ballast water treatment system.\nThe ship will need to demonstrate that any bypass of the system will not be a risk to the environment and should only be\nused as a last resort.\n( Engine Room Procedures Guide 2024)\nBallast Water Biosecurity Risks\nAn Active Substance (AS) is defined as ‘a substance or organism, including a virus or a fungus, that has a general or specific\naction on or against harmful aquatic organisms and pathogens’.\nBWMS that use Active Substances (electro-chlorination & chemical-based)\nRepeated ‘low TRO’ alarms during uptake: The Total Residual Oxidant (TRO) sensor is a critical component of a properly\ninstalled BWMS as it measures if ballast water is treated within the system design limits. Repeated ‘low TRO’ or similar\nalarms during uptake may indicate that the ballast water has not been effectively treated due to an insufficient dose or\ngeneration of Active Substance (AS). If ballast water is treated with an AS at a concentration below the lower alarm limit of\nthe system, an increased level of inspection may apply.\n‘High TRO’ alarms during discharge: This alarm could indicate a problem with neutralisation. If the AS in the ballast water\nis not properly neutralised, the ballast water may cause marine pollution. Commonly encountered issues include seized\nmetering pumps, insufficient or incorrectly mixed neutraliser in the neutraliser tank, blocked TRO sensor pipes, expired TRO\nreagents, and incorrectly arranged valves.\n‘TRO Communication’ alarm: During uptake, TRO production by the electrolyser or dosage from the chemical tank is linked\nto the values obtained by the TRO sensor. If the sensor is not properly reporting the AS concentration to the BWMS, then\nthe treatment may not be effective. Further analysis of the error code on the TRO unit could be required. Common problems\ninclude intake valves not opened, intake lines blocked, dirty cuvette, expired reagents, or seized TRO pumps.\nBWMS that use ultra-violet (UV) light\nThese systems rely on UV light to inactivate or kill organisms in the ballast water and often treat on uptake and discharge.\nThe systems use multiple sensors for UV intensity, temperature, water turbidity, and water flow to maintain effective\ntreatment.\nAlarms indicate that the system may not be treating the ballast water effectively. Continually operating when there are\nrepeated alarms for low light intensity, high filter differential pressure, low water flow, or high temperature may result in a\ndetailed inspection and a direction to stop discharge.\n( AUS Gov- Department of Agriculture,Fisheries and Forestry 2025)\nThe TRO sensor measures the amount of free chlorine or chlorine compounds present in the ballast water after it has been\ntreated by the Ballast Water Treatment System . The TRO sensor is used to evaluate the efficiency of the treatment process.\nThe TRO level indicates how effective the treatment has been in killing harmful organisms and pathogens. If the TRO is\noperating outside the permitted tolerance levels, it may indicate that the treatment has not been effective. The result could\nmean that the ballast water may still contain harmful organisms or there is too much chlorine (Cl2) in the ballast water.\nThe TRO sensor should be maintained and calibrated as per the manufacturer’s recommendations.\nAll ships with an approved BWMP should maintain record-keeping of ballast water operations in the BWRB in accordance\nwith guidance BWM.2/Circ.80. They should also apply the codes A to H, together with the specific item number for different\nballast water operations specified in MEPC.369(80).\nIf the approved electronic record books are provided and the hard copy record book is replaced by an electronic one, a ship-\nspecific declaration must be carried on board. This declaration should confirm that the installation of the electronic system\ndesigned to record entries in accordance with the BWM Convention meets the requirements of the IMO guidelines.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.11","internal_question_no":"05A.011","question_sort_key":5101100.097,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":75,"source_page_end":75,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.12","internal_question_no":"05A.012","question_sort_key":5101200.098,"question_text":"If ballast tanks are located adjacent to fuel oil tanks, or there is a possibility of contamination by hydraulic oil, are ballast tank contents being checked to ensure there has been no contamination of the water by oil prior to discharge?","guide_to_inspection":"There have been cases where fuel has leaked into ballast water tanks due to fractures, pitting or corrosion in the shared\nbulkhead between the tanks. This can lead to substantial financial losses and penalties if the contaminated ballast water is\ndischarged at sea.\nBallast tanks adjacent to bunker tanks, or those with bunker lines running through them, need to be monitored for potential\nleaks from nearby bunker tanks or bunker lines. It’s crucial that ballast water, if it contains an oil sheen on the surface, is not\ndischarged. Monitoring these ballast tanks may involve one of several options. These could include checking the quality\nof the water inside the ballast tanks by visually inspecting the surface, drawing samples from the tanks, or monitoring the\natmosphere within the tanks by installing a gas sampling system.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":75,"source_page_end":75,"raw_source_text":"If ballast tanks are located adjacent to fuel oil tanks, or there is a possibility of contamination by\nhydraulic oil, are ballast tank contents being checked to ensure there has been no contamination of\nthe water by oil prior to discharge? (V)\nGuide to Inspection\nThere have been cases where fuel has leaked into ballast water tanks due to fractures, pitting or corrosion in the shared\nbulkhead between the tanks. This can lead to substantial financial losses and penalties if the contaminated ballast water is\ndischarged at sea.\nBallast tanks adjacent to bunker tanks, or those with bunker lines running through them, need to be monitored for potential\nleaks from nearby bunker tanks or bunker lines. It’s crucial that ballast water, if it contains an oil sheen on the surface, is not\ndischarged. Monitoring these ballast tanks may involve one of several options. These could include checking the quality\nof the water inside the ballast tanks by visually inspecting the surface, drawing samples from the tanks, or monitoring the\natmosphere within the tanks by installing a gas sampling system.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.13","internal_question_no":"05A.013","question_sort_key":5101300.099,"question_text":"Are the emergency bilge suction and emergency overboard discharge valves in the engine room in good order and clearly identified with a notice warning against accidental opening and, is the area around the bilge injection suction bellmouth clear of debris and clean?","guide_to_inspection":"The inspector shall review the test procedure of emergency suction valves.\nEmergency bilge discharge valves and other overboard discharge valves of a similar nature that are normally closed\nare sealed in the closed position with numbered seals. The SMS should implement a suitable method, either manual or\nelectronic, for recording the changes in the process, including removal and replacement of numbered seal tags, testing of\nvalves, maintenance, and other operational requirements. In accordance with MSC-MEPC.4/Circ.3, the sealing of valves of an\nemergency nature shall not be construed as a requirement for the valve to be blanked or physically locked. It shall be ensured\nthat such valves always remain available for use in case of an emergency, and valve sealing may be accomplished through\nuse of a breakable seal, electronic tracking, or similar method.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":75,"source_page_end":75,"raw_source_text":"Are the emergency bilge suction and emergency overboard discharge valves in the engine room in\ngood order and clearly identified with a notice warning against accidental opening and, is the area\naround the bilge injection suction bellmouth clear of debris and clean? (V)\nGuide to Inspection\nThe inspector shall review the test procedure of emergency suction valves.\nEmergency bilge discharge valves and other overboard discharge valves of a similar nature that are normally closed\nare sealed in the closed position with numbered seals. The SMS should implement a suitable method, either manual or\nelectronic, for recording the changes in the process, including removal and replacement of numbered seal tags, testing of\nvalves, maintenance, and other operational requirements. In accordance with MSC-MEPC.4/Circ.3, the sealing of valves of an\nemergency nature shall not be construed as a requirement for the valve to be blanked or physically locked. It shall be ensured\nthat such valves always remain available for use in case of an emergency, and valve sealing may be accomplished through\nuse of a breakable seal, electronic tracking, or similar method.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.14","internal_question_no":"05A.014","question_sort_key":5101400.1,"question_text":"Are arrangements for sludge collecting pumps free from any connection to a direct overboard discharge?","guide_to_inspection":"Sludge collecting pumps are pumps capable of taking suction from any oil residue (sludge) producing equipment or tank,\nother than an oil residue (sludge) tank(s) and discharging only to oil residue (sludge) tank(s).\n(MEPC.1/Circ.642, Revised Guidelines for Systems for Handling Oily Wastes in Machinery\nSpaces of Ships Incorporating Guidance Notes for an Integrated Bilge Water Treatment System (IBTS), 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":75,"source_page_end":75,"raw_source_text":"Are arrangements for sludge collecting pumps free from any connection to a direct overboard discharge? (V)\nGuide to Inspection\nSludge collecting pumps are pumps capable of taking suction from any oil residue (sludge) producing equipment or tank,\nother than an oil residue (sludge) tank(s) and discharging only to oil residue (sludge) tank(s).\n(MEPC.1/Circ.642, Revised Guidelines for Systems for Handling Oily Wastes in Machinery\nSpaces of Ships Incorporating Guidance Notes for an Integrated Bilge Water Treatment System (IBTS), 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ41$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 4/15 imported.' AS result,
  '04A.029' AS chunk_first_question,
  '05A.014' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
